import type { LocalizedTutorialContent } from '../tutorials-longform-i18n';

// Localized long-form content for one tutorial. Generated from validated
// per-locale translation JSONs; en renders from the Markdown source.
export const entry: Partial<Record<string, LocalizedTutorialContent>> = {
  "zh": {
    title: "Open Design 是每个 Vibe Coder 的梦想",
    summary: "一份面向 vibe coder 的 Open Design 实战手册——用上你自己的 agent，挑一套设计系统来摆脱 AI 的廉价感，用提示词搭出真正能转化的结构，再把粗糙的 PRD 在几分钟内变成一个落地页、一个移动应用和一个桌面应用。基于 Sean Kochel 的实操演示。",
    bodyHtml: "<p>这份指南是一本面向 vibe coder 的 Open Design 实战手册：用上你早已在用的 agent，挑一套设计系统，让产出不再一眼就让人喊出“这是 AI 生成的”，用提示词搭出真正能转化的结构，再通过对话不断迭代。它跟着 <strong>Sean Kochel</strong> 在<a href=\"https://www.youtube.com/watch?v=MmTBkDmunk4\">他的实操演示</a>中接连完成的三个项目走——一个落地页、一个移动应用、一个桌面应用——并根据当前版本重新撰写、更新。想看现场实操就看上方的视频，想看文字版就继续往下读。</p>\n<p><img src=\"/tutorials/open-design-vibe-coders-dream-sean-kochel/01-workspace.webp\" alt=\"Open Design 工作区——安装后你看到的第一个界面。\">\n<em>Open Design 工作区——原型、幻灯片、图片和视频，全都在一块从容而熟悉的画布上。</em></p>\n<h2 id=\"what-is-open-design\">什么是 Open Design？</h2>\n<p>Open Design 是一个开源、本地优先的设计平台，它<strong>跑在你早已在用的编程 agent 之上</strong>。它会检测你机器上已有的 CLI——Claude Code、Codex、Cursor、Gemini、Copilot、OpenCode，还有几十种其他工具——并让那个 agent 来驱动生成。用 Sean 的话说：有一个 CLI 层用来配置你的 agent，一段系统提示词驱动质量，然后是真正让它有价值的部分——skill 支持和一个深厚的设计系统库。产出的是真实的 HTML 文件，所以你做出来的东西能直接放进你真正的项目里。</p>\n<p>vibe coder 为什么在意它：</p>\n<ul>\n<li><strong>用你自己的 agent 和密钥</strong>——不用再订阅第二份服务，也没有供应商锁定。</li>\n<li><strong>本地运行</strong>——产出是 HTML，可以直接搬进你的代码库。</li>\n<li><strong>设计系统消灭 AI 廉价感</strong>——从一个真实品牌出发，而不是一张空白画布。</li>\n<li><strong>skill 可定制</strong>——把你自己的文案规则、UX 范式或流程直接放进去。</li>\n<li><strong>开源，Apache-2.0</strong>——读它、fork 它、用它交付客户项目。</li>\n</ul>\n<h2 id=\"the-two-problems-every-vibe-build-runs-into\">每个 vibe 项目都会撞上的两个问题</h2>\n<p>Sean 把整套工作流围绕两种失败模式来组织，它们值得被点名，因为这本手册接下来的内容就是教你如何避开它们：</p>\n<ol>\n<li><strong>看起来像 AI 廉价货。</strong>千篇一律的渐变、同一款衬线字体、一堆套娃容器——连你自己都不喜欢。</li>\n<li><strong>它的结构撑不起它的目的。</strong>一个不会转化的落地页，一个流程说不通的应用。</li>\n</ol>\n<p>一套<strong>设计系统</strong>解决第一个问题。一段<strong>带真实结构的精心提示词</strong>解决第二个问题。接下来每个项目都要把这两点记在心里。</p>\n<h2 id=\"step-1--install-and-pick-your-agent\">第 1 步——安装并选择你的 agent</h2>\n<p>你有三种入门方式：</p>\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n<table><thead><tr><th>方式</th><th>适合谁</th><th>前置要求</th></tr></thead><tbody><tr><td><strong>桌面应用</strong></td><td>大多数人——零配置</td><td>无。下载打开即可。</td></tr><tr><td><strong>从源码运行</strong></td><td>想读或改代码的开发者</td><td>Node <code>~24</code>，pnpm <code>10.33.x</code></td></tr><tr><td><strong>装进你的 agent</strong></td><td>常驻终端的人</td><td>一个已有的编程 agent CLI</td></tr></tbody></table>\n<p>最快的方式是<strong>桌面应用</strong>——到 <a href=\"https://open-design.ai/download\">open-design.ai/download</a> 下载；它会自动检测你 <code>PATH</code> 上已有的 agent CLI。如果想改用源码运行：</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>打开它打印出来的本地 URL（它用的是动态端口——不要写死某个端口）。首次启动时，把 Open Design 指向你想用来驱动工作的那个 agent，或者用你自己的 API 密钥。</p>\n<h2 id=\"step-2--build-a-landing-page-that-converts\">第 2 步——做一个能转化的落地页</h2>\n<p>这是 Sean 的第一个演示，也是后面所有项目的模板：</p>\n<ol>\n<li><strong>挑一套设计系统。</strong>演示里他选了 Anthropic 的。这是你抵御廉价感的护栏——agent 会继承那个品牌的配色、字体和组件语言。</li>\n</ol>\n<p><img src=\"/tutorials/open-design-vibe-coders-dream-sean-kochel/02-design-systems.webp\" alt=\"内置的设计系统库——真实品牌的起点。\">\n<em>设计系统库：每一项都把一个真实品牌拆解成配色、排版、组件，以及你可以复用的视觉氛围。</em></p>\n<ol start=\"2\">\n<li><strong>提示结构，而不只是氛围。</strong>Sean 明确告诉它要做哪些板块——一共十一个——并把他 PRD 里的执行摘要（产品愿景、问题陈述、目标用户、提议方案、核心功能）粘进去，这样文案才有真实的上下文可依。</li>\n<li><strong>回答它的探询问题。</strong>和 Claude Design 一样，Open Design 在动笔前会问澄清性问题。这里它调用自己的 <strong>SaaS 落地页 skill</strong> 来执行——而因为 skill 不过是文件，你完全可以换成加载你自己的文案准则或板块结构作为 skill。</li>\n<li><strong>让它跑起来。</strong>大约五分钟后，他就拿到了一个专业的初稿——一个真正以转化为导向的结构、一张清爽的对比表、一张排版精美的案例卡片、一段扎实的 FAQ。</li>\n</ol>\n<p>想要不一样的感觉？Sean 用完全相同的需求说明，把语气从编辑风换成<strong>粗野主义（brutalist）</strong>，得到了一个明显不同的设计——结构相同，外皮不同，因为重活都是设计系统在干。</p>\n<h2 id=\"step-3--build-a-mobile-app-screen-by-screen\">第 3 步——逐屏搭建一个移动应用</h2>\n<p>在移动端演示里，Sean 一次只做一个界面。他沿用同一套 Anthropic 设计系统，然后为每个界面粘进一段从 PRD 搭出来的提示词——一个首页信息流、一个“查漏补缺”推荐界面、一个随手记的饮食日志。agent 会问它的澄清问题，模拟出一个 iOS 布局，并在三个界面上始终遵循所选的设计系统。</p>\n<p>这里的启示是：<strong>你怎么提示 UX，决定了结果的大部分。</strong>当他把同一个应用重新设想成一个以聊天为先的教练式界面时，他得到了一组截然不同——但依然自洽——的界面。设计系统让它保持品牌一致；你的提示词决定范式。</p>\n<p><img src=\"/tutorials/open-design-vibe-coders-dream-sean-kochel/03-templates.webp\" alt=\"模板库——原型、幻灯片、图片和视频的起点。\">\n<em>模板库：原型、幻灯片、图片和视频的起点，可以按类型筛选并 fork 后开工。</em></p>\n<h2 id=\"step-4--go-multimodal-screens-to-desktop-app\">第 4 步——玩转多模态：从界面到桌面应用</h2>\n<p>最后一个演示展示了多模态的妙处。Sean <strong>把他的三个移动界面截图，丢进一个新的对话，然后给出一个开放式的请求</strong>：“给这套核心功能模拟一个 web 应用版本。”五分钟后，他就有了一个干净的三栏桌面版译写——导航在左、工作画布居中、进度视图在右——连斜杠命令的交互也一并模拟了出来。</p>\n<p>哪怕只是一段模糊的提示词加上参考图，也能给你一个可用的起点。有一份正经的规格说明，结果会更锐利，但核心结论不变：你可以在不同载体之间自由流动。</p>\n<h2 id=\"tips\">小贴士</h2>\n<ul>\n<li><strong>永远从设计系统出发。</strong>它是对抗 AI 廉价感最有力的单一杠杆。</li>\n<li><strong>明确地提示结构。</strong>把板块或界面一一列出来；从 PRD 粘进真实上下文，文案才不空洞。</li>\n<li><strong>善用 skill——也写你自己的。</strong>skill 不过是文件；把你的文案规则或 UX 范式直接加载进工作流。</li>\n<li><strong>通过对话迭代。</strong>不同的 UX 设定会产出非常不同的结果；这是一个特性，所以多试几种。</li>\n<li><strong>用好参考图。</strong>把已有界面截图丢进去，在不同载体之间译写。</li>\n<li><strong>记住产出是 HTML。</strong>它生来就是为了放进一个你已经动工的项目里。</li>\n</ul>\n<h2 id=\"faq\">FAQ</h2>\n<p><strong>我必须用某个特定的模型吗？</strong>\n不用。Open Design 会驱动你配置好的任何 agent——Claude Code、Codex、Cursor、Gemini、OpenCode 等等——或者用你自己的 API 密钥。没有供应商锁定。</p>\n<p><strong>这和 Claude Design 有什么不同？</strong>\n同样熟悉的感觉，但它免费、开源、本地优先、与模型无关，而且可定制程度高得多——你可以加进自己的 skill 和流程。再加上单一供应商工具给不了你的图片和视频生成能力。</p>\n<p><strong>我能把做出来的东西并入一个已有的应用吗？</strong>\n可以——产出是 HTML 文件，就是为了放进一个你已经动工的项目而生的。Sean 在一个配套视频里讲了以规格驱动的合并工作流。</p>\n<p><strong>它免费吗？</strong>\n这个应用在 Apache-2.0 下开源，本地运行免费。你只需为接入的那个 agent 和那些供应商所用的模型与媒体用量付费。</p>\n<hr>\n<p><em>这份文字指南基于 Sean Kochel 的实操演示。观看上方的完整视频，并<a href=\"https://www.youtube.com/watch?v=MmTBkDmunk4\">订阅 Sean Kochel</a> 以获取更多 AI 构建工作流。</em></p>",
  },
  "ja": {
    title: "Open Design はすべてのバイブコーダーの夢",
    summary: "Open Design のためのバイブコーダー向け実践ガイド——自分のエージェントを持ち込み、AI スロップを排除するデザインシステムを選び、コンバージョンする構造をプロンプトで指示し、ラフな PRD をランディングページ、モバイルアプリ、デスクトップアプリへと数分で仕上げる。Sean Kochel の実演デモに基づく。",
    bodyHtml: "<p>このガイドは、Open Design のためのバイブコーダー向け実践ガイドです。すでに使っているエージェントを持ち込み、アウトプットが「AI 生成丸出し」にならないようデザインシステムを選び、実際にコンバージョンする構造をプロンプトで指示し、あとは会話で反復していきます。本記事は <strong>Sean Kochel</strong> が<a href=\"https://www.youtube.com/watch?v=MmTBkDmunk4\">実演デモ</a>で立て続けに行う 3 つのビルド——ランディングページ、モバイルアプリ、デスクトップアプリ——を、最新リリースに合わせて書き直し、文章としてまとめたものです。ライブの実演は上の動画で、テキスト版は以下でご覧ください。</p>\n<p><img src=\"/tutorials/open-design-vibe-coders-dream-sean-kochel/01-workspace.webp\" alt=\"Open Design のワークスペース——インストール後に最初にたどり着く画面。\">\n<em>Open Design のワークスペース——プロトタイプ、スライドデッキ、画像、動画が、落ち着いた使い慣れた一つのキャンバスに集約されている。</em></p>\n<h2 id=\"what-is-open-design\">Open Design とは?</h2>\n<p>Open Design は、<strong>すでに使っているコーディングエージェントの上で動く</strong>、オープンソースかつローカルファーストのデザインプラットフォームです。マシンにすでにある CLI——Claude Code、Codex、Cursor、Gemini、Copilot、OpenCode、そしてさらに数十種類——を検出し、そのエージェントに生成を担わせます。Sean の言葉を借りれば、エージェントを設定する CLI レイヤーがあり、品質を引き出すシステムプロンプトがあり、そしてそれを価値あるものにする部分——スキルのサポートと、デザインシステムの豊富なライブラリ——があります。アウトプットは本物の HTML ファイルなので、作ったものはそのまま実際のプロジェクトに組み込めます。</p>\n<p>バイブコーダーが注目する理由:</p>\n<ul>\n<li><strong>自分のエージェントとキーを持ち込める</strong>——2 つ目のサブスクリプションも、プロバイダーのロックインもなし。</li>\n<li><strong>ローカルで動く</strong>——アウトプットはそのままコードベースに引き上げられる HTML。</li>\n<li><strong>デザインシステムが AI スロップ感を排除する</strong>——白紙のキャンバスではなく、本物のブランドから始められる。</li>\n<li><strong>スキルはカスタマイズ可能</strong>——独自のコピーライティングルール、UX パラダイム、プロセスを組み込める。</li>\n<li><strong>オープンソース、Apache-2.0</strong>——読んで、フォークして、クライアントワークに使える。</li>\n</ul>\n<h2 id=\"the-two-problems-every-vibe-build-runs-into\">どのバイブビルドでもぶつかる 2 つの問題</h2>\n<p>Sean はワークフロー全体を 2 つの失敗パターンを軸に組み立てています。残りの実践ガイドはこれらをどう避けるかの話なので、ここで名前を付けておく価値があります:</p>\n<ol>\n<li><strong>AI スロップに見える。</strong>ありきたりなグラデーション、いつもの同じセリフフォント、コンテナの寄せ集め——自分でも気に入らない。</li>\n<li><strong>役割を果たすように構造化されていない。</strong>コンバージョンしないランディングページ、フローが意味をなさないアプリ。</li>\n</ol>\n<p><strong>デザインシステム</strong>が問題その 1 を解決します。<strong>本物の構造を備えた意図的なプロンプト</strong>が問題その 2 を解決します。以下のどのビルドでも、この両方を念頭に置いてください。</p>\n<h2 id=\"step-1--install-and-pick-your-agent\">ステップ 1 — インストールしてエージェントを選ぶ</h2>\n<p>入り口は 3 通りあります:</p>\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n<table><thead><tr><th>方法</th><th>向いている人</th><th>必要なもの</th></tr></thead><tbody><tr><td><strong>デスクトップアプリ</strong></td><td>ほとんどの人——設定不要</td><td>なし。ダウンロードして開くだけ。</td></tr><tr><td><strong>ソースから実行</strong></td><td>コードを読んだり改変したい開発者</td><td>Node <code>~24</code>、pnpm <code>10.33.x</code></td></tr><tr><td><strong>エージェントに組み込む</strong></td><td>ターミナルで生活する人</td><td>既存のコーディングエージェント CLI</td></tr></tbody></table>\n<p>最速の入り口は<strong>デスクトップアプリ</strong>です——<a href=\"https://open-design.ai/download\">open-design.ai/download</a> から入手しましょう。すでに <code>PATH</code> 上にあるエージェント CLI を自動検出します。代わりにソースから実行するには:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>表示されるローカル URL を開きます(ポートは動的に割り当てられます——決め打ちしないでください)。初回起動時に、作業を担わせたいエージェントを Open Design に指定するか、自分の API キーを持ち込みます。</p>\n<h2 id=\"step-2--build-a-landing-page-that-converts\">ステップ 2 — コンバージョンするランディングページを作る</h2>\n<p>これは Sean の最初のデモで、それ以外すべてのテンプレートになります:</p>\n<ol>\n<li><strong>デザインシステムを選ぶ。</strong>デモでは彼は Anthropic のものを選びます。これがアンチスロップのガードレールです——エージェントはそのブランドのパレット、タイポグラフィ、コンポーネント言語を継承します。</li>\n</ol>\n<p><img src=\"/tutorials/open-design-vibe-coders-dream-sean-kochel/02-design-systems.webp\" alt=\"組み込みのデザインシステムライブラリ——本物のブランドを起点に。\">\n<em>デザインシステムライブラリ:各エントリは本物のブランドを、再利用できるパレット、タイポグラフィ、コンポーネント、ビジュアルの雰囲気へと分解している。</em></p>\n<ol start=\"2\">\n<li><strong>雰囲気だけでなく構造をプロンプトする。</strong>Sean はどのセクションを作るかを正確に指示し——11 個——そして自分の PRD からエグゼクティブサマリー(プロダクトビジョン、課題定義、ターゲットユーザー、提案するソリューション、主要機能)を貼り付けて、コピーが本物の文脈から書き起こせるようにします。</li>\n<li><strong>ディスカバリーの質問に答える。</strong>Claude Design と同様に、Open Design は書き始める前に明確化のための質問をします。ここではそれを実行するために <strong>SaaS ランディングページスキル</strong>を呼び出します——そしてスキルは単なるファイルなので、代わりに自分のコピーライティングガイドラインやセクション構造をスキルとして読み込ませることもできます。</li>\n<li><strong>実行させる。</strong>約 5 分後、彼はプロ品質のファーストパスを手にします——本物のコンバージョン志向の構造、すっきりした比較表、きれいにスタイリングされたケーススタディカード、しっかりした FAQ。</li>\n</ol>\n<p>別のテイストが欲しい? Sean はまったく同じブリーフを、エディトリアルではなく<strong>ブルータリスト</strong>なトーンで再実行し、明らかに違うデザインを得ます——同じ構造、違う皮。デザインシステムが重い仕事を引き受けているからです。</p>\n<h2 id=\"step-3--build-a-mobile-app-screen-by-screen\">ステップ 3 — モバイルアプリを画面ごとに作る</h2>\n<p>モバイルのデモでは、Sean は一度に 1 画面ずつ作業します。同じ Anthropic のデザインシステムを保ったまま、各画面ごとに PRD から組み立てたプロンプトを貼り付けます——ホームフィード、「ギャップを埋める」レコメンド画面、その場で記録するフードログ。エージェントは明確化のための質問をし、iOS のレイアウトをモックアップし、3 つの画面すべてで選んだデザインシステムを守ります。</p>\n<p>得られる教訓は:<strong>UX をどうプロンプトするかが結果のほとんどを決める。</strong>同じアプリをチャットファーストのコーチングインターフェースとして再構成すると、まったく違う——それでも一貫した——画面群が得られます。デザインシステムがブランドの統一を保ち、プロンプトがパラダイムを決めます。</p>\n<p><img src=\"/tutorials/open-design-vibe-coders-dream-sean-kochel/03-templates.webp\" alt=\"テンプレートライブラリ——プロトタイプ、スライド、画像、動画の出発点。\">\n<em>テンプレートライブラリ:プロトタイプ、スライド、画像、動画の出発点。種類でフィルタリングし、フォークして始められる。</em></p>\n<h2 id=\"step-4--go-multimodal-screens-to-desktop-app\">ステップ 4 — マルチモーダルへ:画面からデスクトップアプリへ</h2>\n<p>最後のデモはマルチモーダルの妙技を見せます。Sean は<strong>3 つのモバイル画面のスクリーンショットを撮り、新しいチャットにドロップし、オープンエンドな依頼をします</strong>:「このコア機能のウェブアプリ版をモックアップして」。5 分後、彼はすっきりした 3 ペインのデスクトップ版を手にします——左にナビゲーション、中央に作業キャンバス、右に進捗ビュー——スラッシュコマンドのインタラクションもモックアップ済みです。</p>\n<p>曖昧なプロンプトでも、参照画像を添えれば使える出発点が得られます。きちんとした仕様があればさらにシャープになりますが、要点は変わりません:サーフェス間を自在に行き来できるのです。</p>\n<h2 id=\"tips\">ヒント</h2>\n<ul>\n<li><strong>常にデザインシステムから始める。</strong>AI スロップ感に対抗する最大の一手だ。</li>\n<li><strong>構造を明示的にプロンプトする。</strong>セクションや画面を列挙し、PRD から本物の文脈を貼り付けてコピーが空疎にならないようにする。</li>\n<li><strong>スキルを活用し——自分でも書く。</strong>スキルは単なるファイル。自分のコピーライティングルールや UX パラダイムをそのままワークフローに読み込ませよう。</li>\n<li><strong>会話で反復する。</strong>UX のフレーミングが違えば結果も大きく変わる。それは機能なので、いくつか試してみよう。</li>\n<li><strong>参照画像を使う。</strong>既存の画面をスクリーンショットしてドロップし、サーフェスをまたいで変換しよう。</li>\n<li><strong>アウトプットは HTML だと覚えておく。</strong>すでに始めているプロジェクトに組み込めるように作られている。</li>\n</ul>\n<h2 id=\"faq\">FAQ</h2>\n<p><strong>特定のモデルを使わなければなりませんか?</strong>\nいいえ。Open Design は設定したエージェント——Claude Code、Codex、Cursor、Gemini、OpenCode など——や自分の API キーで動きます。プロバイダーのロックインはありません。</p>\n<p><strong>Claude Design とどう違うのですか?</strong>\n使い慣れた感覚は同じですが、無料で、オープンソースで、ローカルファーストで、モデル非依存で、はるかにカスタマイズ性が高い——独自のスキルやプロセスを追加できます。さらに、単一プロバイダーのツールでは得られない画像生成と動画生成も。</p>\n<p><strong>作ったものを既存のアプリにマージできますか?</strong>\nはい——アウトプットは HTML ファイルなので、すでに始めているプロジェクトに組み込めるように作られています。Sean は仕様駆動のマージワークフローを別の動画で扱っています。</p>\n<p><strong>無料ですか?</strong>\nアプリは Apache-2.0 のオープンソースで、ローカルで無料で実行できます。料金がかかるのは、接続したエージェントとプロバイダーのモデルとメディアの使用分だけです。</p>\n<hr>\n<p><em>この記事は Sean Kochel の実演デモに基づいています。上のフル動画をご覧になり、AI ビルドのワークフローをもっと知りたい方は <a href=\"https://www.youtube.com/watch?v=MmTBkDmunk4\">Sean Kochel をチャンネル登録</a>してください。</em></p>",
  },
  "ko": {
    title: "Open Design은 모든 바이브 코더의 꿈입니다",
    summary: "Open Design을 위한 바이브 코더 플레이북 — 이미 쓰던 에이전트를 그대로 가져오고, AI 슬롭을 잡아줄 디자인 시스템을 고르고, 전환을 일으키는 구조를 프롬프트로 지시한 다음, 거친 PRD를 단 몇 분 만에 랜딩 페이지, 모바일 앱, 데스크톱 앱으로 바꿔보세요. Sean Kochel의 실전 데모를 바탕으로 합니다.",
    bodyHtml: "<p>이 가이드는 Open Design을 위한 바이브 코더의 플레이북입니다. 이미 쓰고 있는 에이전트를 그대로 가져오고, 결과물이 “AI가 만든 티”를 내지 않도록 디자인 시스템을 고르고, 실제로 전환을 일으키는 구조를 프롬프트로 지시한 다음, 대화를 통해 반복 개선합니다. 이 글은 <strong>Sean Kochel</strong>이 <a href=\"https://www.youtube.com/watch?v=MmTBkDmunk4\">자신의 실전 데모</a>에서 연달아 진행하는 세 가지 빌드 — 랜딩 페이지, 모바일 앱, 데스크톱 앱 — 를 따라가며, 현재 릴리스에 맞춰 다시 쓰고 최신화한 내용입니다. 라이브 실행을 보려면 위 영상을, 글로 읽고 싶다면 아래를 이어서 보세요.</p>\n<p><img src=\"/tutorials/open-design-vibe-coders-dream-sean-kochel/01-workspace.webp\" alt=\"Open Design 워크스페이스 — 설치 후 처음 마주하는 화면.\">\n<em>Open Design 워크스페이스 — 프로토타입, 슬라이드 덱, 이미지, 비디오를 차분하고 익숙한 하나의 캔버스에 담았습니다.</em></p>\n<h2 id=\"what-is-open-design\">Open Design이란?</h2>\n<p>Open Design은 <strong>이미 쓰고 있는 코딩 에이전트 위에서</strong> 동작하는 오픈소스, 로컬 우선 디자인 플랫폼입니다. 머신에 이미 설치된 CLI들 — Claude Code, Codex, Cursor, Gemini, Copilot, OpenCode, 그리고 수십 개가 더 있습니다 — 을 감지해 그 에이전트가 생성을 주도하게 합니다. Sean의 말을 빌리면, 에이전트를 설정하는 CLI 레이어가 있고, 품질을 끌어올리는 시스템 프롬프트가 있으며, 그다음에 진짜 가치를 만들어 내는 부분 — 스킬 지원과 방대한 디자인 시스템 라이브러리 — 이 있습니다. 결과물은 실제 HTML 파일이므로, 무엇을 만들든 그대로 여러분의 실제 프로젝트에 떨어집니다.</p>\n<p>바이브 코더가 주목하는 이유:</p>\n<ul>\n<li><strong>자신의 에이전트와 키를 그대로 사용</strong> — 두 번째 구독도, 공급자 종속도 없습니다.</li>\n<li><strong>로컬에서 실행</strong> — 결과물은 코드베이스에 바로 옮겨 넣을 수 있는 HTML입니다.</li>\n<li><strong>디자인 시스템이 AI 슬롭 느낌을 잡아줍니다</strong> — 빈 캔버스가 아니라 실제 브랜드에서 시작합니다.</li>\n<li><strong>스킬은 커스터마이즈 가능</strong> — 자신만의 카피라이팅 규칙, UX 패러다임, 프로세스를 넣을 수 있습니다.</li>\n<li><strong>오픈소스, Apache-2.0</strong> — 읽고, 포크하고, 클라이언트 작업에 쓰세요.</li>\n</ul>\n<h2 id=\"the-two-problems-every-vibe-build-runs-into\">모든 바이브 빌드가 부딪히는 두 가지 문제</h2>\n<p>Sean은 전체 워크플로를 두 가지 실패 양상을 중심으로 설명합니다. 나머지 플레이북 전체가 이 두 가지를 피하는 방법이기 때문에 짚어볼 가치가 있습니다:</p>\n<ol>\n<li><strong>AI 슬롭처럼 보인다.</strong> 뻔한 그래디언트, 똑같은 세리프 폰트, 컨테이너 범벅 — 만든 본인조차 마음에 들지 않습니다.</li>\n<li><strong>제 역할을 하도록 구조화되어 있지 않다.</strong> 전환되지 않는 랜딩 페이지, 흐름이 말이 안 되는 앱.</li>\n</ol>\n<p><strong>디자인 시스템</strong>이 첫 번째 문제를 해결합니다. <strong>실제 구조를 갖춘 의도적인 프롬프트</strong>가 두 번째 문제를 해결합니다. 아래의 모든 빌드에서 이 둘을 염두에 두세요.</p>\n<h2 id=\"step-1--install-and-pick-your-agent\">1단계 — 설치하고 에이전트를 고르세요</h2>\n<p>들어가는 방법은 세 가지입니다:</p>\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n<table><thead><tr><th>경로</th><th>적합한 대상</th><th>요구 사항</th></tr></thead><tbody><tr><td><strong>데스크톱 앱</strong></td><td>대부분의 사람 — 설정이 전혀 필요 없음</td><td>없음. 다운로드해서 열기만 하면 됩니다.</td></tr><tr><td><strong>소스에서 실행</strong></td><td>코드를 읽거나 수정하고 싶은 개발자</td><td>Node <code>~24</code>, pnpm <code>10.33.x</code></td></tr><tr><td><strong>에이전트에 설치</strong></td><td>터미널에서 사는 사람</td><td>기존 코딩 에이전트 CLI</td></tr></tbody></table>\n<p>가장 빠른 경로는 <strong>데스크톱 앱</strong>입니다 — <a href=\"https://open-design.ai/download\">open-design.ai/download</a>에서 받으세요. 여러분의 <code>PATH</code>에 이미 있는 에이전트 CLI를 자동으로 감지합니다. 대신 소스에서 실행하려면:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>출력되는 로컬 URL을 여세요(동적 포트를 사용하므로 포트를 하드코딩하지 마세요). 처음 실행할 때 Open Design이 작업을 주도할 에이전트를 지정하거나, 자신의 API 키를 가져오세요.</p>\n<h2 id=\"step-2--build-a-landing-page-that-converts\">2단계 — 전환되는 랜딩 페이지 만들기</h2>\n<p>이것이 Sean의 첫 번째 데모이며, 나머지 모든 작업의 템플릿이 됩니다:</p>\n<ol>\n<li><strong>디자인 시스템을 고르세요.</strong> 데모에서 그는 Anthropic의 디자인 시스템을 선택합니다. 이것이 슬롭 방지 가드레일입니다 — 에이전트가 그 브랜드의 팔레트, 타이포그래피, 컴포넌트 언어를 물려받습니다.</li>\n</ol>\n<p><img src=\"/tutorials/open-design-vibe-coders-dream-sean-kochel/02-design-systems.webp\" alt=\"내장 디자인 시스템 라이브러리 — 실제 브랜드 출발점들.\">\n<em>디자인 시스템 라이브러리: 각 항목이 실제 브랜드를 팔레트, 타이포그래피, 컴포넌트, 시각적 분위기로 분해해 재사용할 수 있게 해줍니다.</em></p>\n<ol start=\"2\">\n<li><strong>분위기뿐 아니라 구조를 프롬프트하세요.</strong> Sean은 어떤 섹션을 만들지 정확히 — 열한 개를 — 지시하고, 자신의 PRD에서 가져온 경영 요약(제품 비전, 문제 정의, 타깃 사용자, 제안 솔루션, 핵심 기능)을 붙여 넣어 카피가 실제 맥락을 바탕으로 작성되게 합니다.</li>\n<li><strong>디스커버리 질문에 답하세요.</strong> Claude Design과 마찬가지로, Open Design은 작성하기 전에 명확히 하는 질문을 던집니다. 여기서는 실행을 위해 <strong>SaaS 랜딩 페이지 스킬</strong>을 가져다 씁니다 — 그리고 스킬은 그저 파일이기 때문에, 대신 자신만의 카피라이팅 가이드라인이나 섹션 구조를 스킬로 불러올 수도 있습니다.</li>\n<li><strong>실행되게 두세요.</strong> 약 5분 뒤에 전문적인 첫 결과물이 나옵니다 — 실제 전환 지향 구조, 깔끔한 비교 표, 보기 좋게 스타일링된 사례 연구 카드, 탄탄한 FAQ까지.</li>\n</ol>\n<p>다른 느낌을 원하나요? Sean은 똑같은 브리프를 에디토리얼 대신 <strong>브루탈리스트</strong> 톤으로 다시 실행해, 의미 있게 다른 디자인을 얻습니다 — 구조는 같고 껍데기만 다릅니다. 디자인 시스템이 무거운 일을 대신해 주기 때문입니다.</p>\n<h2 id=\"step-3--build-a-mobile-app-screen-by-screen\">3단계 — 화면 단위로 모바일 앱 만들기</h2>\n<p>모바일 데모에서 Sean은 한 번에 한 화면씩 작업합니다. 같은 Anthropic 디자인 시스템을 유지한 채, 각 화면마다 자신의 PRD를 바탕으로 만든 프롬프트를 붙여 넣습니다 — 홈 피드, “빈틈 채우기” 추천 화면, 즉석 음식 기록. 에이전트는 명확히 하는 질문을 던지고, iOS 레이아웃을 목업하며, 세 화면 모두에서 선택한 디자인 시스템을 일관되게 따릅니다.</p>\n<p>교훈은 이렇습니다: <strong>UX를 어떻게 프롬프트하느냐가 결과의 대부분을 좌우한다.</strong> 그가 같은 앱을 채팅 우선의 코칭 인터페이스로 다시 짜자, 전혀 다르지만 여전히 일관된 화면 세트를 얻습니다. 디자인 시스템이 브랜드 일관성을 지키고, 프롬프트가 패러다임을 결정합니다.</p>\n<p><img src=\"/tutorials/open-design-vibe-coders-dream-sean-kochel/03-templates.webp\" alt=\"템플릿 라이브러리 — 프로토타입, 슬라이드, 이미지, 비디오 출발점들.\">\n<em>템플릿 라이브러리: 유형별로 필터링하고 포크해서 시작할 수 있는 프로토타입, 슬라이드, 이미지, 비디오 출발점들.</em></p>\n<h2 id=\"step-4--go-multimodal-screens-to-desktop-app\">4단계 — 멀티모달로 가기: 화면에서 데스크톱 앱으로</h2>\n<p>마지막 데모는 멀티모달 트릭을 보여줍니다. Sean은 <strong>모바일 화면 세 개를 스크린샷으로 찍어 새 채팅에 넣고, 열린 형태의 요청을 던집니다</strong>: “이 핵심 기능의 웹 앱 버전을 목업해줘.” 5분 뒤에 깔끔한 3분할 데스크톱 변환본이 나옵니다 — 왼쪽에 내비게이션, 가운데에 작업 캔버스, 오른쪽에 진행 상황 뷰 — 슬래시 커맨드 상호작용까지 목업되어 있습니다.</p>\n<p>모호한 프롬프트에 참고 이미지만 더해도 쓸 만한 출발점이 나옵니다. 제대로 된 스펙이 있으면 더 선명해지지만, 요점은 그대로입니다: 여러 표면 사이를 자유롭게 오갈 수 있다는 것입니다.</p>\n<h2 id=\"tips\">팁</h2>\n<ul>\n<li><strong>항상 디자인 시스템에서 시작하세요.</strong> AI 슬롭 느낌에 맞서는 가장 큰 단일 지렛대입니다.</li>\n<li><strong>구조를 명시적으로 프롬프트하세요.</strong> 섹션이나 화면을 나열하고, PRD에서 가져온 실제 맥락을 붙여 넣어 카피가 공허하지 않게 하세요.</li>\n<li><strong>스킬에 기대고 — 자신만의 스킬도 작성하세요.</strong> 스킬은 그저 파일입니다. 카피라이팅 규칙이나 UX 패러다임을 워크플로에 바로 불러오세요.</li>\n<li><strong>대화로 반복 개선하세요.</strong> UX 프레이밍이 달라지면 결과가 크게 달라집니다. 그것이 기능이니, 여러 가지를 시도해 보세요.</li>\n<li><strong>참고 이미지를 활용하세요.</strong> 기존 화면을 스크린샷으로 찍어 넣어 표면을 넘나들며 변환하세요.</li>\n<li><strong>결과물이 HTML이라는 점을 기억하세요.</strong> 이미 시작한 프로젝트에 떨어뜨려 넣도록 만들어졌습니다.</li>\n</ul>\n<h2 id=\"faq\">FAQ</h2>\n<p><strong>특정 모델을 꼭 써야 하나요?</strong>\n아니요. Open Design은 여러분이 설정한 어떤 에이전트든 — Claude Code, Codex, Cursor, Gemini, OpenCode 등 — 또는 자신의 API 키로 구동합니다. 공급자 종속이 없습니다.</p>\n<p><strong>Claude Design과는 어떻게 다른가요?</strong>\n익숙한 느낌은 같지만, 무료이고 오픈소스이며 로컬 우선이고 모델에 구애받지 않으며 훨씬 더 커스터마이즈하기 좋습니다 — 자신만의 스킬과 프로세스를 추가할 수 있습니다. 게다가 단일 공급자 도구로는 얻을 수 없는 이미지·비디오 생성 기능까지 있습니다.</p>\n<p><strong>만든 것을 기존 앱에 병합할 수 있나요?</strong>\n네 — 결과물이 HTML 파일이므로, 이미 시작한 프로젝트에 떨어뜨려 넣도록 만들어졌습니다. Sean은 스펙 기반 병합 워크플로를 별도 영상에서 다룹니다.</p>\n<p><strong>무료인가요?</strong>\n앱은 Apache-2.0 라이선스의 오픈소스이며 로컬에서 무료로 실행할 수 있습니다. 비용은 연결한 에이전트와 공급자의 모델 및 미디어 사용분에 대해서만 발생합니다.</p>\n<hr>\n<p><em>이 글로 된 가이드는 Sean Kochel의 실전 데모를 바탕으로 합니다. 위의 전체 영상을 보고, 더 많은 AI 빌드 워크플로를 보려면 <a href=\"https://www.youtube.com/watch?v=MmTBkDmunk4\">Sean Kochel을 구독하세요</a>.</em></p>",
  },
  "de": {
    title: "Open Design ist der Traum jedes Vibe Coders",
    summary: "Ein Vibe-Coder-Playbook für Open Design — bring deinen eigenen Agenten mit, wähle ein Designsystem, um AI-Slop abzuwürgen, prompte für eine Struktur, die konvertiert, und verwandle grobe PRDs in Minuten in eine Landingpage, eine mobile App und eine Desktop-App. Basierend auf den praxisnahen Demos von Sean Kochel.",
    bodyHtml: "<p>Dieser Leitfaden ist ein Vibe-Coder-Playbook für Open Design: Bring den Agenten mit, den du ohnehin schon nutzt, wähle ein Designsystem, damit dein Output nicht „KI-generiert“ schreit, prompte für eine Struktur, die wirklich konvertiert, und iteriere dann im Gespräch. Er folgt den drei aufeinanderfolgenden Builds, die <strong>Sean Kochel</strong> in <a href=\"https://www.youtube.com/watch?v=MmTBkDmunk4\">seinen praxisnahen Demos</a> durchspielt — eine Landingpage, eine mobile App und eine Desktop-App — neu geschrieben und auf den aktuellen Stand des heutigen Release gebracht. Sieh dir das Video oben für den Live-Durchlauf an oder lies weiter für die schriftliche Fassung.</p>\n<p><img src=\"/tutorials/open-design-vibe-coders-dream-sean-kochel/01-workspace.webp\" alt=\"Der Open-Design-Workspace — das, was dich nach der Installation erwartet.\">\n<em>Der Open-Design-Workspace — Prototypen, Foliensätze, Bilder und Video auf einer ruhigen, vertrauten Leinwand.</em></p>\n<h2 id=\"what-is-open-design\">Was ist Open Design?</h2>\n<p>Open Design ist eine quelloffene, local-first Designplattform, die <strong>auf dem Coding-Agenten aufsetzt, den du ohnehin schon nutzt</strong>. Sie erkennt die CLIs, die bereits auf deinem Rechner liegen — Claude Code, Codex, Cursor, Gemini, Copilot, OpenCode und ein paar Dutzend mehr — und lässt diesen Agenten die Generierung steuern. So formuliert es Sean: Es gibt eine CLI-Ebene, auf der du deinen Agenten konfigurierst, einen System-Prompt, der die Qualität antreibt, und dann die Teile, die das Ganze wertvoll machen — die Skill-Unterstützung und eine umfangreiche Bibliothek von Designsystemen. Die Outputs sind echte HTML-Dateien, sodass alles, was du erstellst, direkt in dein tatsächliches Projekt fällt.</p>\n<p>Warum Vibe Coder das interessiert:</p>\n<ul>\n<li><strong>Bring deinen eigenen Agenten und Key mit</strong> — kein zweites Abo, kein Anbieter-Lock-in.</li>\n<li><strong>Läuft lokal</strong> — der Output ist HTML, das du direkt in deine Codebasis übernehmen kannst.</li>\n<li><strong>Designsysteme killen den AI-Slop-Look</strong> — starte von einer echten Marke statt von einer leeren Leinwand.</li>\n<li><strong>Skills sind anpassbar</strong> — bring deine eigenen Copywriting-Regeln, UX-Paradigmen oder Abläufe ein.</li>\n<li><strong>Open Source, Apache-2.0</strong> — lies ihn, forke ihn, liefere damit Kundenarbeit aus.</li>\n</ul>\n<h2 id=\"the-two-problems-every-vibe-build-runs-into\">Die zwei Probleme, in die jeder Vibe-Build läuft</h2>\n<p>Sean rahmt den gesamten Workflow um zwei Fehlermodi, und es lohnt sich, sie zu benennen, denn der Rest des Playbooks erklärt, wie du sie vermeidest:</p>\n<ol>\n<li><strong>Es sieht aus wie AI-Slop.</strong> Generische Verläufe, dieselbe Serifenschrift, Container-Suppe — du magst es nicht mal selbst.</li>\n<li><strong>Es ist nicht so strukturiert, dass es seinen Job erfüllt.</strong> Eine Landingpage, die nicht konvertiert, eine App, deren Flow keinen Sinn ergibt.</li>\n</ol>\n<p>Ein <strong>Designsystem</strong> löst Problem eins. Ein <strong>bewusster Prompt mit echter Struktur</strong> löst Problem zwei. Behalte beide bei jedem Build weiter unten im Kopf.</p>\n<h2 id=\"step-1--install-and-pick-your-agent\">Schritt 1 — Installieren und deinen Agenten wählen</h2>\n<p>Du hast drei Wege hinein:</p>\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n<table><thead><tr><th>Weg</th><th>Am besten geeignet für</th><th>Voraussetzungen</th></tr></thead><tbody><tr><td><strong>Desktop-App</strong></td><td>Die meisten — null Konfiguration</td><td>Keine. Einfach herunterladen und öffnen.</td></tr><tr><td><strong>Aus dem Quellcode laufen lassen</strong></td><td>Entwickler, die den Code lesen oder anpassen wollen</td><td>Node <code>~24</code>, pnpm <code>10.33.x</code></td></tr><tr><td><strong>In deinen Agenten installieren</strong></td><td>Leute, die im Terminal leben</td><td>Eine bestehende Coding-Agent-CLI</td></tr></tbody></table>\n<p>Der schnellste Weg ist die <strong>Desktop-App</strong> — hol sie dir von <a href=\"https://open-design.ai/download\">open-design.ai/download</a>; sie erkennt automatisch die Agent-CLIs, die bereits in deinem <code>PATH</code> liegen. So lässt du es stattdessen aus dem Quellcode laufen:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>Öffne die lokale URL, die ausgegeben wird (sie nutzt einen dynamischen Port — kodiere keinen fest). Beim ersten Start richtest du Open Design auf den Agenten aus, der die Arbeit antreiben soll, oder bringst deinen eigenen API-Key mit.</p>\n<h2 id=\"step-2--build-a-landing-page-that-converts\">Schritt 2 — Eine Landingpage bauen, die konvertiert</h2>\n<p>Das ist Seans erste Demo, und sie ist die Vorlage für alles Weitere:</p>\n<ol>\n<li><strong>Wähle ein Designsystem.</strong> In der Demo entscheidet er sich für das von Anthropic. Das ist dein Anti-Slop-Schutzgeländer — der Agent erbt Palette, Typografie und Komponentensprache dieser Marke.</li>\n</ol>\n<p><img src=\"/tutorials/open-design-vibe-coders-dream-sean-kochel/02-design-systems.webp\" alt=\"Die eingebaute Designsystem-Bibliothek — echte Markenstartpunkte.\">\n<em>Die Designsystem-Bibliothek: Jeder Eintrag zerlegt eine echte Marke in Palette, Typografie, Komponenten und visuelle Atmosphäre, die du wiederverwenden kannst.</em></p>\n<ol start=\"2\">\n<li><strong>Prompte die Struktur, nicht nur das Gefühl.</strong> Sean sagt genau, welche Abschnitte gebaut werden sollen — elf davon — und fügt die Executive Summary aus seinem PRD ein (Produktvision, Problembeschreibung, Zielnutzer, vorgeschlagene Lösung, Hauptfunktionen), damit der Text echten Kontext hat, mit dem er arbeiten kann.</li>\n<li><strong>Beantworte die Discovery-Fragen.</strong> Genau wie Claude Design stellt Open Design klärende Fragen, bevor es schreibt. Hier greift es zu seinem <strong>SaaS-Landingpage-Skill</strong>, um die Aufgabe auszuführen — und weil Skills einfach Dateien sind, könntest du stattdessen deine eigenen Copywriting-Richtlinien oder deine Abschnittsstruktur als Skill laden.</li>\n<li><strong>Lass es laufen.</strong> Etwa fünf Minuten später hat er einen professionellen ersten Wurf — eine echte konversionsorientierte Struktur, eine saubere Vergleichstabelle, eine schön gestaltete Fallstudien-Karte, ein solides FAQ.</li>\n</ol>\n<p>Du willst ein anderes Gefühl? Sean lässt genau denselben Brief noch einmal mit einem <strong>brutalistischen</strong> Ton statt einem redaktionellen laufen und erhält ein deutlich anderes Design — gleiche Struktur, andere Haut, weil das Designsystem die schwere Arbeit übernimmt.</p>\n<h2 id=\"step-3--build-a-mobile-app-screen-by-screen\">Schritt 3 — Eine mobile App bauen, Screen für Screen</h2>\n<p>Für die Mobile-Demo arbeitet Sean Screen für Screen. Er behält dasselbe Anthropic-Designsystem bei und fügt dann für jeden Screen einen aus seinem PRD aufgebauten Prompt ein — einen Home-Feed, einen „Fülle die Lücken“-Empfehlungsscreen, ein Ad-hoc-Ernährungstagebuch. Der Agent stellt seine klärenden Fragen, mockt ein iOS-Layout und hält sich über alle drei Screens hinweg an das gewählte Designsystem.</p>\n<p>Die Lektion: <strong>Wie du die UX promptest, ist der größte Teil des Ergebnisses.</strong> Als er dieselbe App als chat-first Coaching-Interface neu rahmt, bekommt er eine völlig andere — aber dennoch kohärente — Reihe von Screens. Das Designsystem hält es markenkonform; dein Prompt entscheidet über das Paradigma.</p>\n<p><img src=\"/tutorials/open-design-vibe-coders-dream-sean-kochel/03-templates.webp\" alt=\"Die Vorlagenbibliothek — Startpunkte für Prototyp, Folie, Bild und Video.\">\n<em>Die Vorlagenbibliothek: Startpunkte für Prototyp, Folie, Bild und Video, die du nach Typ filtern und zum Loslegen forken kannst.</em></p>\n<h2 id=\"step-4--go-multimodal-screens-to-desktop-app\">Schritt 4 — Multimodal werden: von Screens zur Desktop-App</h2>\n<p>Die letzte Demo zeigt den multimodalen Trick. Sean <strong>macht Screenshots seiner drei mobilen Screens, legt sie in einen neuen Chat und stellt eine offene Anfrage</strong>: „Mocke eine Web-App-Version dieser Kernfunktionalität.“ Fünf Minuten später hat er eine saubere Desktop-Übersetzung mit drei Bereichen — Navigation links, die Arbeitsleinwand in der Mitte, eine Fortschrittsansicht rechts — wobei auch die Slash-Befehl-Interaktionen mitgemockt sind.</p>\n<p>Schon ein vager Prompt plus Referenzbilder verschafft dir einen nutzbaren Ausgangspunkt. Mit einer ordentlichen Spezifikation wird es schärfer, aber der Kern bleibt: Du kannst dich flüssig zwischen den Oberflächen bewegen.</p>\n<h2 id=\"tips\">Tipps</h2>\n<ul>\n<li><strong>Starte immer von einem Designsystem.</strong> Es ist der mit Abstand größte Hebel gegen den AI-Slop-Look.</li>\n<li><strong>Prompte die Struktur explizit.</strong> Liste die Abschnitte oder Screens auf; füge echten Kontext aus einem PRD ein, damit der Text nicht hohl ist.</li>\n<li><strong>Stütze dich auf Skills — und schreib deine eigenen.</strong> Skills sind einfach Dateien; lade deine Copywriting-Regeln oder UX-Paradigmen direkt in den Workflow.</li>\n<li><strong>Iteriere im Gespräch.</strong> Eine andere UX-Rahmung liefert sehr unterschiedliche Ergebnisse; das ist ein Feature, also probiere ein paar aus.</li>\n<li><strong>Nutze Referenzbilder.</strong> Mach Screenshots bestehender Screens und leg sie ein, um zwischen Oberflächen zu übersetzen.</li>\n<li><strong>Denk daran, dass der Output HTML ist.</strong> Er ist dafür gebaut, in ein Projekt zu fallen, das du bereits begonnen hast.</li>\n</ul>\n<h2 id=\"faq\">FAQ</h2>\n<p><strong>Muss ich ein bestimmtes Modell verwenden?</strong>\nNein. Open Design steuert jeden Agenten, den du konfiguriert hast — Claude Code, Codex, Cursor, Gemini, OpenCode und mehr — oder deinen eigenen API-Key. Kein Anbieter-Lock-in.</p>\n<p><strong>Wie unterscheidet sich das von Claude Design?</strong>\nGleiches vertrautes Gefühl, aber kostenlos, quelloffen, local-first, modellunabhängig und weitaus anpassbarer — du kannst eigene Skills und Abläufe hinzufügen. Dazu Bild- und Videogenerierung, die ein Single-Provider-Tool dir nicht bietet.</p>\n<p><strong>Kann ich das, was ich baue, in eine bestehende App einbinden?</strong>\nJa — die Outputs sind HTML-Dateien, also sind sie dafür gedacht, in ein Projekt zu fallen, das du bereits begonnen hast. Sean behandelt spezifikationsgetriebene Merge-Workflows in einem Begleitvideo.</p>\n<p><strong>Ist es kostenlos?</strong>\nDie App ist Open Source unter Apache-2.0 und kostenlos lokal lauffähig. Du zahlst nur für die Modell- und Mediennutzung des jeweiligen Agenten und der Anbieter, die du anschließt.</p>\n<hr>\n<p><em>Dieser schriftliche Leitfaden basiert auf Sean Kochels praxisnahen Demos. Sieh dir das vollständige Video oben an und <a href=\"https://www.youtube.com/watch?v=MmTBkDmunk4\">abonniere Sean Kochel</a> für weitere AI-Build-Workflows.</em></p>",
  },
  "fr": {
    title: "Open Design est le rêve de tout vibe coder",
    summary: "Le manuel du vibe coder pour Open Design : apportez votre propre agent, choisissez un design system pour en finir avec l'esthétique « IA générée », rédigez un prompt pour une structure qui convertit, et transformez des PRD bruts en une landing page, une application mobile et une application de bureau en quelques minutes. D'après les démonstrations pratiques de Sean Kochel.",
    bodyHtml: "<p>Ce guide est le manuel du vibe coder pour Open Design : apportez l'agent que vous utilisez déjà, choisissez un design system pour que votre résultat ne crie pas « généré par IA », rédigez un prompt pour une structure qui convertit réellement, puis itérez par la conversation. Il suit les trois projets enchaînés que <strong>Sean Kochel</strong> réalise dans <a href=\"https://www.youtube.com/watch?v=MmTBkDmunk4\">ses démonstrations pratiques</a> — une landing page, une application mobile et une application de bureau — réécrits et mis à jour avec la version actuelle. Regardez la vidéo ci-dessus pour la démonstration en direct, ou poursuivez votre lecture pour la version écrite.</p>\n<p><img src=\"/tutorials/open-design-vibe-coders-dream-sean-kochel/01-workspace.webp\" alt=\"L'espace de travail Open Design — ce que vous découvrez après l'installation.\">\n<em>L'espace de travail Open Design — prototypes, présentations, images et vidéos réunis dans un même canevas, calme et familier.</em></p>\n<h2 id=\"what-is-open-design\">Qu'est-ce qu'Open Design ?</h2>\n<p>Open Design est une plateforme de design open source et local-first qui fonctionne <strong>par-dessus l'agent de code que vous utilisez déjà</strong>. Elle détecte les CLI déjà présents sur votre machine — Claude Code, Codex, Cursor, Gemini, Copilot, OpenCode, et une vingtaine d'autres — et laisse cet agent piloter la génération. Comme le dit Sean : il y a une couche CLI où vous configurez votre agent, un system prompt qui pilote la qualité, puis les éléments qui font toute la valeur — la prise en charge des skills et une vaste bibliothèque de design systems. Les sorties sont de vrais fichiers HTML, donc tout ce que vous créez s'intègre directement dans votre projet réel.</p>\n<p>Pourquoi les vibe coders y trouvent leur compte :</p>\n<ul>\n<li><strong>Apportez votre propre agent et votre clé</strong> — pas de deuxième abonnement, pas d'enfermement chez un fournisseur.</li>\n<li><strong>Fonctionne en local</strong> — le résultat est du HTML que vous pouvez reprendre tel quel dans votre base de code.</li>\n<li><strong>Les design systems éliminent l'esthétique « IA »</strong> — partez d'une vraie marque plutôt que d'une page blanche.</li>\n<li><strong>Les skills sont personnalisables</strong> — ajoutez vos propres règles de rédaction, paradigmes UX ou processus.</li>\n<li><strong>Open source, Apache-2.0</strong> — lisez-le, forkez-le, livrez du travail client avec.</li>\n</ul>\n<h2 id=\"the-two-problems-every-vibe-build-runs-into\">Les deux problèmes que rencontre tout projet en vibe coding</h2>\n<p>Sean structure tout le workflow autour de deux modes d'échec, et il vaut la peine de les nommer car le reste du manuel explique comment les éviter :</p>\n<ol>\n<li><strong>Ça ressemble à de la bouillie d'IA.</strong> Des dégradés génériques, la même police serif, une soupe de conteneurs — un résultat que vous n'aimez même pas vous-même.</li>\n<li><strong>Ce n'est pas structuré pour remplir sa mission.</strong> Une landing page qui ne convertit pas, une application dont le parcours n'a pas de sens.</li>\n</ol>\n<p>Un <strong>design system</strong> résout le premier problème. Un <strong>prompt réfléchi avec une vraie structure</strong> résout le second. Gardez les deux à l'esprit pour chacun des projets ci-dessous.</p>\n<h2 id=\"step-1--install-and-pick-your-agent\">Étape 1 — Installer et choisir votre agent</h2>\n<p>Vous avez trois portes d'entrée :</p>\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n<table><thead><tr><th>Voie</th><th>Idéale pour</th><th>Prérequis</th></tr></thead><tbody><tr><td><strong>Application de bureau</strong></td><td>La plupart des gens — zéro configuration</td><td>Aucun. Il suffit de télécharger et d'ouvrir.</td></tr><tr><td><strong>Exécuter depuis les sources</strong></td><td>Les développeurs qui veulent lire ou modifier le code</td><td>Node <code>~24</code>, pnpm <code>10.33.x</code></td></tr><tr><td><strong>Installer dans votre agent</strong></td><td>Ceux qui vivent dans le terminal</td><td>Un CLI d'agent de code existant</td></tr></tbody></table>\n<p>La voie la plus rapide est l'<strong>application de bureau</strong> — récupérez-la sur <a href=\"https://open-design.ai/download\">open-design.ai/download</a> ; elle détecte automatiquement les CLI d'agent déjà présents dans votre <code>PATH</code>. Pour l'exécuter depuis les sources :</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>Ouvrez l'URL locale qu'il affiche (il utilise un port dynamique — ne le codez pas en dur). Au premier lancement, indiquez à Open Design l'agent que vous voulez voir piloter le travail, ou apportez votre propre clé API.</p>\n<h2 id=\"step-2--build-a-landing-page-that-converts\">Étape 2 — Construire une landing page qui convertit</h2>\n<p>C'est la première démonstration de Sean, et elle sert de modèle à tout le reste :</p>\n<ol>\n<li><strong>Choisissez un design system.</strong> Dans la démonstration, il choisit celui d'Anthropic. C'est votre garde-fou anti-bouillie — l'agent hérite de la palette, de la typographie et du langage de composants de cette marque.</li>\n</ol>\n<p><img src=\"/tutorials/open-design-vibe-coders-dream-sean-kochel/02-design-systems.webp\" alt=\"La bibliothèque de design systems intégrée — de vrais points de départ de marques.\">\n<em>La bibliothèque de design systems : chaque entrée décompose une vraie marque en palette, typographie, composants et atmosphère visuelle que vous pouvez réutiliser.</em></p>\n<ol start=\"2\">\n<li><strong>Rédigez le prompt pour la structure, pas seulement pour l'ambiance.</strong> Sean lui indique précisément quelles sections construire — onze au total — et colle le résumé exécutif de son PRD (vision produit, énoncé du problème, utilisateur cible, solution proposée, fonctionnalités principales) pour que le texte dispose d'un vrai contexte de travail.</li>\n<li><strong>Répondez aux questions de découverte.</strong> Tout comme Claude Design, Open Design pose des questions de clarification avant d'écrire. Ici, il fait appel à son <strong>skill de landing page SaaS</strong> pour exécuter — et comme les skills ne sont que des fichiers, vous pourriez à la place charger vos propres consignes de rédaction ou votre structure de sections sous forme de skill.</li>\n<li><strong>Laissez-le travailler.</strong> Environ cinq minutes plus tard, il obtient un premier jet professionnel — une vraie structure orientée conversion, un tableau comparatif soigné, une fiche d'étude de cas joliment stylisée, une FAQ solide.</li>\n</ol>\n<p>Envie d'un ressenti différent ? Sean relance exactement le même brief avec un ton <strong>brutaliste</strong> plutôt qu'éditorial et obtient un design nettement différent — même structure, habillage différent, parce que le design system fait le gros du travail.</p>\n<h2 id=\"step-3--build-a-mobile-app-screen-by-screen\">Étape 3 — Construire une application mobile, écran par écran</h2>\n<p>Pour la démonstration mobile, Sean travaille un écran à la fois. Il garde le même design system Anthropic, puis pour chaque écran colle un prompt construit à partir de son PRD — un fil d'actualité d'accueil, un écran de recommandations « comblez les manques », un journal alimentaire ponctuel. L'agent pose ses questions de clarification, maquette une mise en page iOS et respecte le design system choisi sur les trois écrans.</p>\n<p>La leçon : <strong>la façon dont vous formulez le prompt pour l'UX détermine l'essentiel du résultat.</strong> Lorsqu'il reformule la même application comme une interface de coaching centrée sur le chat, il obtient un ensemble d'écrans radicalement différent — mais toujours cohérent. Le design system la maintient fidèle à la marque ; votre prompt décide du paradigme.</p>\n<p><img src=\"/tutorials/open-design-vibe-coders-dream-sean-kochel/03-templates.webp\" alt=\"La bibliothèque de templates — points de départ pour prototypes, présentations, images et vidéos.\">\n<em>La bibliothèque de templates : des points de départ pour prototypes, présentations, images et vidéos, que vous pouvez filtrer par type et forker pour commencer.</em></p>\n<h2 id=\"step-4--go-multimodal-screens-to-desktop-app\">Étape 4 — Passer au multimodal : des écrans à l'application de bureau</h2>\n<p>La dernière démonstration montre l'astuce multimodale. Sean <strong>fait des captures d'écran de ses trois écrans mobiles, les dépose dans un nouveau chat et formule une demande ouverte</strong> : « maquette une version application web de cette fonctionnalité de base ». Cinq minutes plus tard, il obtient une transposition propre vers le bureau en trois volets — la navigation à gauche, le canevas de travail au centre, une vue de progression à droite — avec les interactions par commandes slash maquettées elles aussi.</p>\n<p>Même un prompt vague accompagné d'images de référence vous donne un point de départ utilisable. Avec une spécification en bonne et due forme, c'est plus précis, mais l'idée tient : vous pouvez passer d'une surface à l'autre avec fluidité.</p>\n<h2 id=\"tips\">Conseils</h2>\n<ul>\n<li><strong>Partez toujours d'un design system.</strong> C'est le plus puissant des leviers contre l'esthétique « IA ».</li>\n<li><strong>Rédigez explicitement le prompt pour la structure.</strong> Listez les sections ou les écrans ; collez un vrai contexte issu d'un PRD pour que le texte ne sonne pas creux.</li>\n<li><strong>Appuyez-vous sur les skills — et écrivez les vôtres.</strong> Les skills ne sont que des fichiers ; chargez vos règles de rédaction ou vos paradigmes UX directement dans le workflow.</li>\n<li><strong>Itérez par la conversation.</strong> Un cadrage UX différent produit des résultats très différents ; c'est une fonctionnalité, alors essayez-en plusieurs.</li>\n<li><strong>Utilisez des images de référence.</strong> Faites des captures d'écran existantes et déposez-les pour transposer d'une surface à l'autre.</li>\n<li><strong>Rappelez-vous que la sortie est du HTML.</strong> Elle est conçue pour s'intégrer à un projet que vous avez déjà démarré.</li>\n</ul>\n<h2 id=\"faq\">FAQ</h2>\n<p><strong>Dois-je utiliser un modèle particulier ?</strong>\nNon. Open Design pilote l'agent que vous avez configuré — Claude Code, Codex, Cursor, Gemini, OpenCode, et d'autres — ou votre propre clé API. Aucun enfermement chez un fournisseur.</p>\n<p><strong>En quoi est-ce différent de Claude Design ?</strong>\nMême ressenti familier, mais gratuit, open source, local-first, agnostique vis-à-vis du modèle, et bien plus personnalisable — vous pouvez ajouter vos propres skills et processus. Sans oublier la génération d'images et de vidéos qu'un outil mono-fournisseur ne vous offre pas.</p>\n<p><strong>Puis-je fusionner ce que je construis dans une application existante ?</strong>\nOui — les sorties sont des fichiers HTML, donc elles sont faites pour s'intégrer à un projet que vous avez déjà démarré. Sean aborde les workflows de fusion pilotés par spécification dans une vidéo complémentaire.</p>\n<p><strong>Est-ce gratuit ?</strong>\nL'application est open source sous licence Apache-2.0 et gratuite à exécuter en local. Vous ne payez que l'usage du modèle et des médias de l'agent et des fournisseurs que vous connectez.</p>\n<hr>\n<p><em>Ce guide écrit est basé sur les démonstrations pratiques de Sean Kochel. Regardez la vidéo complète ci-dessus, et <a href=\"https://www.youtube.com/watch?v=MmTBkDmunk4\">abonnez-vous à Sean Kochel</a> pour découvrir d'autres workflows de création avec l'IA.</em></p>",
  },
  "ru": {
    title: "Open Design — мечта каждого vibe-кодера",
    summary: "Практическое руководство по Open Design для vibe-кодера: подключите своего агента, выберите дизайн-систему, чтобы избавиться от «AI-мусора», задайте промпт для структуры, которая конвертирует, и превратите черновые PRD в лендинг, мобильное приложение и десктопное приложение за считаные минуты. По мотивам практических демо Шона Кочела (Sean Kochel).",
    bodyHtml: "<p>Это руководство — практический playbook по Open Design для vibe-кодера: подключите того агента, которым вы уже пользуетесь, выберите дизайн-систему, чтобы результат не кричал «сгенерировано ИИ», задайте промпт для структуры, которая действительно конвертирует, и дальше дорабатывайте всё через диалог. Оно повторяет три идущие подряд сборки, которые <strong>Sean Kochel</strong> показывает в <a href=\"https://www.youtube.com/watch?v=MmTBkDmunk4\">своих практических демо</a> — лендинг, мобильное приложение и десктопное приложение — переписанные и обновлённые под текущий релиз. Посмотрите видео выше, чтобы увидеть процесс вживую, или читайте текстовую версию ниже.</p>\n<p><img src=\"/tutorials/open-design-vibe-coders-dream-sean-kochel/01-workspace.webp\" alt=\"Рабочее пространство Open Design — то, что вы видите сразу после установки.\">\n<em>Рабочее пространство Open Design — прототипы, презентации, изображения и видео на одном спокойном и привычном холсте.</em></p>\n<h2 id=\"what-is-open-design\">Что такое Open Design?</h2>\n<p>Open Design — это открытая, local-first дизайн-платформа, которая работает <strong>поверх того кодинг-агента, которым вы уже пользуетесь</strong>. Она находит CLI, уже установленные на вашей машине — Claude Code, Codex, Cursor, Gemini, Copilot, OpenCode и ещё пару десятков других — и позволяет этому агенту управлять генерацией. Как говорит Шон: есть слой CLI, где вы настраиваете своего агента, есть системный промпт, который задаёт качество, а есть то, что делает всё это ценным — поддержка скиллов и обширная библиотека дизайн-систем. Результат — это настоящие HTML-файлы, так что всё, что вы создаёте, ложится прямо в ваш реальный проект.</p>\n<p>Почему это важно для vibe-кодеров:</p>\n<ul>\n<li><strong>Подключаете своего агента и свой ключ</strong> — никаких вторых подписок, никакой привязки к провайдеру.</li>\n<li><strong>Работает локально</strong> — на выходе HTML, который можно перенести прямо в кодовую базу.</li>\n<li><strong>Дизайн-системы убирают вид «AI-мусора»</strong> — вы стартуете с настоящего бренда, а не с чистого листа.</li>\n<li><strong>Скиллы настраиваемы</strong> — добавляйте собственные правила копирайтинга, UX-парадигмы или процессы.</li>\n<li><strong>Открытый код, Apache-2.0</strong> — читайте, форкайте, делайте на нём клиентские проекты.</li>\n</ul>\n<h2 id=\"the-two-problems-every-vibe-build-runs-into\">Две проблемы, с которыми сталкивается любая vibe-сборка</h2>\n<p>Шон строит весь процесс вокруг двух типов провалов, и их стоит назвать, потому что весь остальной playbook — это то, как их избежать:</p>\n<ol>\n<li><strong>Выглядит как AI-мусор.</strong> Шаблонные градиенты, один и тот же serif-шрифт, «суп из контейнеров» — такое вам и самим не нравится.</li>\n<li><strong>Не выстроено под свою задачу.</strong> Лендинг, который не конвертирует; приложение, логика которого не складывается.</li>\n</ol>\n<p><strong>Дизайн-система</strong> решает первую проблему. <strong>Продуманный промпт с реальной структурой</strong> решает вторую. Держите оба пункта в голове для каждой сборки ниже.</p>\n<h2 id=\"step-1--install-and-pick-your-agent\">Шаг 1 — Установите Open Design и выберите агента</h2>\n<p>Есть три способа начать:</p>\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n<table><thead><tr><th>Способ</th><th>Кому подходит</th><th>Требования</th></tr></thead><tbody><tr><td><strong>Десктопное приложение</strong></td><td>Большинству — без настройки</td><td>Ничего. Просто скачайте и откройте.</td></tr><tr><td><strong>Запуск из исходников</strong></td><td>Разработчикам, которые хотят читать или менять код</td><td>Node <code>~24</code>, pnpm <code>10.33.x</code></td></tr><tr><td><strong>Установка в своего агента</strong></td><td>Тем, кто живёт в терминале</td><td>Уже установленный CLI кодинг-агента</td></tr></tbody></table>\n<p>Самый быстрый путь — <strong>десктопное приложение</strong>: скачайте его с <a href=\"https://open-design.ai/download\">open-design.ai/download</a>; оно само находит CLI агентов, уже доступные в вашем <code>PATH</code>. Чтобы вместо этого запустить из исходников:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>Откройте локальный URL, который она выведет (используется динамический порт — не прописывайте его жёстко). При первом запуске укажите Open Design агента, который будет вести работу, или подключите собственный API-ключ.</p>\n<h2 id=\"step-2--build-a-landing-page-that-converts\">Шаг 2 — Соберите лендинг, который конвертирует</h2>\n<p>Это первое демо Шона, и оно задаёт шаблон для всего остального:</p>\n<ol>\n<li><strong>Выберите дизайн-систему.</strong> В демо он выбирает систему Anthropic. Это ваш барьер против «мусора» — агент наследует палитру, типографику и язык компонентов этого бренда.</li>\n</ol>\n<p><img src=\"/tutorials/open-design-vibe-coders-dream-sean-kochel/02-design-systems.webp\" alt=\"Встроенная библиотека дизайн-систем — отправные точки на основе реальных брендов.\">\n<em>Библиотека дизайн-систем: каждая запись разбирает реальный бренд на палитру, типографику, компоненты и визуальную атмосферу, которые можно переиспользовать.</em></p>\n<ol start=\"2\">\n<li><strong>Прописывайте структуру, а не только настроение.</strong> Шон точно указывает, какие секции построить — их одиннадцать — и вставляет краткое резюме (executive summary) из своего PRD (видение продукта, постановка проблемы, целевой пользователь, предлагаемое решение, ключевые функции), чтобы у текста был реальный контекст для работы.</li>\n<li><strong>Ответьте на уточняющие вопросы.</strong> Как и Claude Design, Open Design задаёт уточняющие вопросы, прежде чем начать писать. Здесь он берёт свой <strong>скилл лендинга для SaaS</strong>, чтобы выполнить задачу — а поскольку скиллы это просто файлы, вместо него вы могли бы загрузить как скилл собственные правила копирайтинга или структуру секций.</li>\n<li><strong>Дайте ему отработать.</strong> Примерно через пять минут у него готов профессиональный первый вариант — реальная структура, ориентированная на конверсию, аккуратная сравнительная таблица, со вкусом оформленная карточка кейса, добротный FAQ.</li>\n</ol>\n<p>Хотите другое ощущение? Шон прогоняет ровно тот же бриф в <strong>брутализме</strong> вместо редакционного стиля и получает заметно другой дизайн — та же структура, другая «обёртка», потому что основную работу делает дизайн-система.</p>\n<h2 id=\"step-3--build-a-mobile-app-screen-by-screen\">Шаг 3 — Соберите мобильное приложение, экран за экраном</h2>\n<p>Для мобильного демо Шон работает по одному экрану за раз. Он сохраняет ту же дизайн-систему Anthropic, а затем для каждого экрана вставляет промпт, собранный из своего PRD — домашняя лента, экран рекомендаций «заполни пробелы», быстрый дневник питания. Агент задаёт уточняющие вопросы, делает макет в стиле iOS и придерживается выбранной дизайн-системы на всех трёх экранах.</p>\n<p>Урок: <strong>то, как вы прописываете UX, определяет бо́льшую часть результата.</strong> Когда он переформулирует то же приложение как chat-first интерфейс коучинга, он получает совершенно другой — но при этом цельный — набор экранов. Дизайн-система удерживает всё в рамках бренда; ваш промпт определяет парадигму.</p>\n<p><img src=\"/tutorials/open-design-vibe-coders-dream-sean-kochel/03-templates.webp\" alt=\"Библиотека шаблонов — отправные точки для прототипов, слайдов, изображений и видео.\">\n<em>Библиотека шаблонов: отправные точки для прототипов, слайдов, изображений и видео, которые можно фильтровать по типу и форкать, чтобы начать.</em></p>\n<h2 id=\"step-4--go-multimodal-screens-to-desktop-app\">Шаг 4 — Перейдите в мультимодальность: от экранов к десктопному приложению</h2>\n<p>Последнее демо показывает мультимодальный трюк. Шон <strong>делает скриншоты своих трёх мобильных экранов, бросает их в новый чат и даёт открытую задачу</strong>: «сделай макет веб-версии этой основной функциональности». Через пять минут у него аккуратный трёхпанельный десктопный вариант — навигация слева, рабочий холст по центру, панель прогресса справа — и взаимодействия через slash-команды тоже намечены.</p>\n<p>Даже размытый промпт плюс референсные изображения дают вам пригодную для работы отправную точку. С нормальной спецификацией всё получается точнее, но суть остаётся: вы можете свободно перемещаться между форматами.</p>\n<h2 id=\"tips\">Советы</h2>\n<ul>\n<li><strong>Всегда начинайте с дизайн-системы.</strong> Это самый мощный рычаг против вида «AI-мусора».</li>\n<li><strong>Прописывайте структуру явно.</strong> Перечислите секции или экраны; вставьте реальный контекст из PRD, чтобы текст не был пустым.</li>\n<li><strong>Опирайтесь на скиллы — и пишите свои.</strong> Скиллы это просто файлы; загружайте свои правила копирайтинга или UX-парадигмы прямо в рабочий процесс.</li>\n<li><strong>Дорабатывайте через диалог.</strong> Разные формулировки UX дают очень разные результаты; это фича, так что попробуйте несколько.</li>\n<li><strong>Используйте референсные изображения.</strong> Делайте скриншоты существующих экранов и подкидывайте их, чтобы переносить идеи между форматами.</li>\n<li><strong>Помните, что на выходе HTML.</strong> Он создан для того, чтобы лечь в уже начатый проект.</li>\n</ul>\n<h2 id=\"faq\">FAQ</h2>\n<p><strong>Обязательно ли использовать конкретную модель?</strong>\nНет. Open Design управляет любым агентом, которого вы настроили — Claude Code, Codex, Cursor, Gemini, OpenCode и другими — или вашим собственным API-ключом. Никакой привязки к провайдеру.</p>\n<p><strong>Чем это отличается от Claude Design?</strong>\nТо же привычное ощущение, но бесплатно, с открытым кодом, local-first, без привязки к модели и куда более настраиваемо — вы можете добавлять собственные скиллы и процессы. Плюс генерация изображений и видео, которой инструмент с одним провайдером вам не даст.</p>\n<p><strong>Могу ли я встроить то, что собрал, в существующее приложение?</strong>\nДа — на выходе HTML-файлы, так что они рассчитаны на то, чтобы лечь в уже начатый проект. Спецификационные сценарии слияния Шон разбирает в отдельном видео.</p>\n<p><strong>Это бесплатно?</strong>\nПриложение с открытым кодом под Apache-2.0 и бесплатно для локального запуска. Вы платите только за использование модели и медиа того агента и тех провайдеров, которых подключаете.</p>\n<hr>\n<p><em>Это текстовое руководство основано на практических демо Шона Кочела (Sean Kochel). Посмотрите полное видео выше и <a href=\"https://www.youtube.com/watch?v=MmTBkDmunk4\">подпишитесь на Sean Kochel</a>, чтобы увидеть больше воркфлоу по сборке на ИИ.</em></p>",
  },
  "es": {
    title: "Open Design es el sueño de todo vibe coder",
    summary: "Un manual para vibe coders sobre Open Design: usa el agente que ya tienes, elige un sistema de diseño para acabar con el «AI slop», escribe prompts pensados para una estructura que convierte y transforma PRD en bruto en una landing page, una app móvil y una app de escritorio en minutos. Basado en las demos prácticas de Sean Kochel.",
    bodyHtml: "<p>Esta guía es un manual para vibe coders sobre Open Design: usa el agente que ya tienes, elige un sistema de diseño para que tu resultado no grite «generado por IA», escribe prompts pensados para una estructura que realmente convierte y luego itera conversando. Sigue las tres construcciones consecutivas que <strong>Sean Kochel</strong> realiza en <a href=\"https://www.youtube.com/watch?v=MmTBkDmunk4\">sus demos prácticas</a> —una landing page, una app móvil y una app de escritorio—, reescritas y actualizadas con la versión actual. Mira el video de arriba para verlo en vivo, o sigue leyendo para la versión escrita.</p>\n<p><img src=\"/tutorials/open-design-vibe-coders-dream-sean-kochel/01-workspace.webp\" alt=\"El espacio de trabajo de Open Design: lo que ves al instalar.\">\n<em>El espacio de trabajo de Open Design: prototipos, presentaciones, imágenes y video en un mismo lienzo tranquilo y familiar.</em></p>\n<h2 id=\"what-is-open-design\">¿Qué es Open Design?</h2>\n<p>Open Design es una plataforma de diseño de código abierto y local-first que se ejecuta <strong>sobre el agente de programación que ya usas</strong>. Detecta los CLI que ya tienes en tu máquina —Claude Code, Codex, Cursor, Gemini, Copilot, OpenCode y un par de docenas más— y deja que ese agente impulse la generación. Como dice Sean: hay una capa de CLI donde configuras tu agente, un system prompt que impulsa la calidad y luego las partes que la hacen valiosa: el soporte de skills y una amplia biblioteca de sistemas de diseño. Los resultados son archivos HTML reales, así que todo lo que crees encaja directamente en tu proyecto real.</p>\n<p>Por qué les importa a los vibe coders:</p>\n<ul>\n<li><strong>Usa tu propio agente y tu clave</strong>: sin una segunda suscripción, sin dependencia de un proveedor.</li>\n<li><strong>Se ejecuta localmente</strong>: el resultado es HTML que puedes llevar directamente a tu base de código.</li>\n<li><strong>Los sistemas de diseño acaban con el aspecto de «AI slop»</strong>: parte de una marca real en lugar de un lienzo en blanco.</li>\n<li><strong>Las skills son personalizables</strong>: incorpora tus propias reglas de copywriting, paradigmas de UX o procesos.</li>\n<li><strong>Código abierto, Apache-2.0</strong>: léelo, haz un fork y entrega trabajo de cliente con él.</li>\n</ul>\n<h2 id=\"the-two-problems-every-vibe-build-runs-into\">Los dos problemas con los que se topa todo vibe build</h2>\n<p>Sean estructura todo el flujo de trabajo en torno a dos modos de fallo, y vale la pena nombrarlos porque el resto del manual trata de cómo evitarlos:</p>\n<ol>\n<li><strong>Parece «AI slop».</strong> Degradados genéricos, la misma fuente serif, una sopa de contenedores: ni a ti mismo te gusta.</li>\n<li><strong>No está estructurado para cumplir su función.</strong> Una landing page que no convierte, una app cuyo flujo no tiene sentido.</li>\n</ol>\n<p>Un <strong>sistema de diseño</strong> resuelve el problema uno. Un <strong>prompt deliberado con una estructura real</strong> resuelve el problema dos. Ten ambos presentes en cada construcción que sigue.</p>\n<h2 id=\"step-1--install-and-pick-your-agent\">Paso 1: Instala y elige tu agente</h2>\n<p>Tienes tres formas de entrar:</p>\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n<table><thead><tr><th>Ruta</th><th>Ideal para</th><th>Requisitos</th></tr></thead><tbody><tr><td><strong>App de escritorio</strong></td><td>La mayoría de la gente: cero configuración</td><td>Ninguno. Solo descárgala y ábrela.</td></tr><tr><td><strong>Ejecutar desde el código fuente</strong></td><td>Desarrolladores que quieren leer o modificar el código</td><td>Node <code>~24</code>, pnpm <code>10.33.x</code></td></tr><tr><td><strong>Instalar en tu agente</strong></td><td>Quienes viven en la terminal</td><td>Un CLI de agente de programación existente</td></tr></tbody></table>\n<p>La ruta más rápida es la <strong>app de escritorio</strong>: consíguela en <a href=\"https://open-design.ai/download\">open-design.ai/download</a>; detecta automáticamente los CLI de agentes que ya están en tu <code>PATH</code>. Para ejecutarla desde el código fuente en su lugar:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>Abre la URL local que imprime (usa un puerto dinámico, no lo fijes a mano). En el primer arranque, apunta Open Design al agente que quieres que dirija el trabajo, o usa tu propia clave de API.</p>\n<h2 id=\"step-2--build-a-landing-page-that-converts\">Paso 2: Construye una landing page que convierte</h2>\n<p>Esta es la primera demo de Sean, y es la plantilla para todo lo demás:</p>\n<ol>\n<li><strong>Elige un sistema de diseño.</strong> En la demo elige el de Anthropic. Esta es tu barrera anti-slop: el agente hereda la paleta, la tipografía y el lenguaje de componentes de esa marca.</li>\n</ol>\n<p><img src=\"/tutorials/open-design-vibe-coders-dream-sean-kochel/02-design-systems.webp\" alt=\"La biblioteca integrada de sistemas de diseño: puntos de partida de marcas reales.\">\n<em>La biblioteca de sistemas de diseño: cada entrada descompone una marca real en paleta, tipografía, componentes y atmósfera visual que puedes reutilizar.</em></p>\n<ol start=\"2\">\n<li><strong>Da un prompt para la estructura, no solo para el estilo.</strong> Sean le indica exactamente qué secciones construir —once de ellas— y pega el resumen ejecutivo de su PRD (visión del producto, planteamiento del problema, usuario objetivo, solución propuesta, funciones principales) para que el copy tenga un contexto real con el que trabajar.</li>\n<li><strong>Responde las preguntas de descubrimiento.</strong> Igual que Claude Design, Open Design hace preguntas aclaratorias antes de escribir. Aquí recurre a su <strong>skill de landing page SaaS</strong> para ejecutar, y como las skills no son más que archivos, podrías cargar tus propias pautas de copywriting o estructura de secciones como una skill en su lugar.</li>\n<li><strong>Déjalo trabajar.</strong> Unos cinco minutos después tiene una primera versión profesional: una estructura real orientada a la conversión, una tabla comparativa limpia, una tarjeta de caso de estudio con buen estilo y unas FAQ sólidas.</li>\n</ol>\n<p>¿Quieres otra sensación? Sean vuelve a ejecutar exactamente el mismo brief con un tono <strong>brutalista</strong> en lugar de editorial y obtiene un diseño notablemente distinto: la misma estructura, otra piel, porque el sistema de diseño hace el trabajo pesado.</p>\n<h2 id=\"step-3--build-a-mobile-app-screen-by-screen\">Paso 3: Construye una app móvil, pantalla por pantalla</h2>\n<p>Para la demo móvil, Sean trabaja una pantalla a la vez. Mantiene el mismo sistema de diseño de Anthropic y luego, para cada pantalla, pega un prompt construido a partir de su PRD: un feed de inicio, una pantalla de recomendaciones para «rellenar los huecos» y un registro de comidas improvisado. El agente hace sus preguntas aclaratorias, crea una maqueta de un layout iOS y respeta el sistema de diseño elegido en las tres pantallas.</p>\n<p>La lección: <strong>cómo escribes el prompt de la UX es la mayor parte del resultado.</strong> Cuando replantea la misma app como una interfaz de coaching centrada en el chat, obtiene un conjunto de pantallas radicalmente distinto, pero igual de coherente. El sistema de diseño la mantiene fiel a la marca; tu prompt decide el paradigma.</p>\n<p><img src=\"/tutorials/open-design-vibe-coders-dream-sean-kochel/03-templates.webp\" alt=\"La biblioteca de plantillas: puntos de partida de prototipos, presentaciones, imágenes y video.\">\n<em>La biblioteca de plantillas: puntos de partida de prototipos, presentaciones, imágenes y video que puedes filtrar por tipo y bifurcar para empezar.</em></p>\n<h2 id=\"step-4--go-multimodal-screens-to-desktop-app\">Paso 4: Hazlo multimodal: de pantallas a app de escritorio</h2>\n<p>La última demo muestra el truco multimodal. Sean <strong>captura sus tres pantallas móviles, las suelta en un chat nuevo y plantea una petición abierta</strong>: «haz una maqueta de una versión web app de esta funcionalidad principal». Cinco minutos después tiene una traducción de escritorio limpia de tres paneles —navegación a la izquierda, el lienzo de trabajo en el centro y una vista de progreso a la derecha— con las interacciones de comandos slash también maquetadas.</p>\n<p>Incluso un prompt vago más imágenes de referencia te da un punto de partida utilizable. Con una especificación adecuada queda más afinado, pero la idea se mantiene: puedes moverte con fluidez entre superficies.</p>\n<h2 id=\"tips\">Consejos</h2>\n<ul>\n<li><strong>Empieza siempre desde un sistema de diseño.</strong> Es la palanca más grande contra el aspecto de «AI slop».</li>\n<li><strong>Da un prompt explícito para la estructura.</strong> Enumera las secciones o pantallas; pega contexto real de un PRD para que el copy no sea hueco.</li>\n<li><strong>Apóyate en las skills, y escribe las tuyas.</strong> Las skills no son más que archivos; carga tus reglas de copywriting o paradigmas de UX directamente en el flujo de trabajo.</li>\n<li><strong>Itera conversando.</strong> Distintos enfoques de UX dan resultados muy distintos; eso es una ventaja, así que prueba varios.</li>\n<li><strong>Usa imágenes de referencia.</strong> Captura pantallas existentes y suéltalas para trasladarlas entre superficies.</li>\n<li><strong>Recuerda que el resultado es HTML.</strong> Está hecho para encajar en un proyecto que ya hayas empezado.</li>\n</ul>\n<h2 id=\"faq\">FAQ</h2>\n<p><strong>¿Tengo que usar un modelo específico?</strong>\nNo. Open Design dirige cualquier agente que hayas configurado —Claude Code, Codex, Cursor, Gemini, OpenCode y más— o tu propia clave de API. Sin dependencia de un proveedor.</p>\n<p><strong>¿En qué se diferencia de Claude Design?</strong>\nLa misma sensación familiar, pero gratis, de código abierto, local-first, agnóstico respecto al modelo y mucho más personalizable: puedes añadir tus propias skills y procesos. Además, generación de imágenes y video que una herramienta de un solo proveedor no te ofrece.</p>\n<p><strong>¿Puedo fusionar lo que construyo en una app existente?</strong>\nSí: los resultados son archivos HTML, así que están pensados para encajar en un proyecto que ya hayas empezado. Sean cubre los flujos de fusión basados en especificaciones en un video complementario.</p>\n<p><strong>¿Es gratis?</strong>\nLa app es de código abierto bajo Apache-2.0 y gratuita para ejecutarse localmente. Solo pagas por el uso de modelo y de medios del agente y los proveedores que conectes.</p>\n<hr>\n<p><em>Esta guía escrita se basa en las demos prácticas de Sean Kochel. Mira el video completo de arriba y <a href=\"https://www.youtube.com/watch?v=MmTBkDmunk4\">suscríbete a Sean Kochel</a> para más flujos de trabajo de construcción con IA.</em></p>",
  },
  "pt-br": {
    title: "Open Design é o sonho de todo vibe coder",
    summary: "Um manual de vibe coding para o Open Design — use o agente que você já tem, escolha um design system para acabar com o visual de \"gerado por IA\", faça prompts pensando em uma estrutura que converte e transforme PRDs rascunhados em uma landing page, um app mobile e um app desktop em minutos. Baseado nas demonstrações práticas de Sean Kochel.",
    bodyHtml: "<p>Este guia é um manual de vibe coding para o Open Design: use o agente que você já usa, escolha um design system para que o resultado não grite “gerado por IA”, faça prompts pensando em uma estrutura que realmente converte e depois itere por conversa. Ele acompanha as três construções consecutivas que <strong>Sean Kochel</strong> realiza em <a href=\"https://www.youtube.com/watch?v=MmTBkDmunk4\">suas demonstrações práticas</a> — uma landing page, um app mobile e um app desktop — reescritas e atualizadas com a versão atual. Assista ao vídeo acima para ver a execução ao vivo, ou continue lendo para a versão em texto.</p>\n<p><img src=\"/tutorials/open-design-vibe-coders-dream-sean-kochel/01-workspace.webp\" alt=\"O workspace do Open Design — o que você encontra logo após a instalação.\">\n<em>O workspace do Open Design — protótipos, apresentações de slides, imagens e vídeo em um único canvas tranquilo e familiar.</em></p>\n<h2 id=\"what-is-open-design\">O que é o Open Design?</h2>\n<p>O Open Design é uma plataforma de design open-source e local-first que roda <strong>em cima do agente de código que você já usa</strong>. Ele detecta as CLIs já presentes na sua máquina — Claude Code, Codex, Cursor, Gemini, Copilot, OpenCode e mais algumas dezenas — e deixa esse agente conduzir a geração. Como Sean coloca: existe uma camada de CLI onde você configura seu agente, um system prompt que conduz a qualidade e, então, as partes que tornam tudo valioso — suporte a skills e uma biblioteca profunda de design systems. As saídas são arquivos HTML reais, então o que você criar entra direto no seu projeto de verdade.</p>\n<p>Por que os vibe coders se importam:</p>\n<ul>\n<li><strong>Use seu próprio agente e sua chave</strong> — sem segunda assinatura, sem aprisionamento a um provedor.</li>\n<li><strong>Roda localmente</strong> — a saída é HTML que você pode levar direto para o seu código.</li>\n<li><strong>Design systems acabam com o visual de slop de IA</strong> — comece a partir de uma marca real em vez de um canvas em branco.</li>\n<li><strong>As skills são personalizáveis</strong> — adicione suas próprias regras de copywriting, paradigmas de UX ou processos.</li>\n<li><strong>Open source, Apache-2.0</strong> — leia, faça fork e entregue trabalho para clientes com isso.</li>\n</ul>\n<h2 id=\"the-two-problems-every-vibe-build-runs-into\">Os dois problemas que todo vibe build enfrenta</h2>\n<p>Sean enquadra todo o fluxo de trabalho em torno de dois modos de falha, e vale a pena nomeá-los porque o resto do manual é justamente como evitá-los:</p>\n<ol>\n<li><strong>Parece slop de IA.</strong> Gradientes genéricos, sempre a mesma fonte serifada, sopa de containers — você mesmo não gosta.</li>\n<li><strong>Não está estruturado para cumprir seu papel.</strong> Uma landing page que não converte, um app cujo fluxo não faz sentido.</li>\n</ol>\n<p>Um <strong>design system</strong> resolve o problema um. Um <strong>prompt deliberado com estrutura real</strong> resolve o problema dois. Tenha os dois em mente em cada construção a seguir.</p>\n<h2 id=\"step-1--install-and-pick-your-agent\">Passo 1 — Instale e escolha seu agente</h2>\n<p>Você tem três formas de entrar:</p>\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n<table><thead><tr><th>Caminho</th><th>Ideal para</th><th>Requisitos</th></tr></thead><tbody><tr><td><strong>App desktop</strong></td><td>A maioria das pessoas — zero configuração</td><td>Nenhum. Basta baixar e abrir.</td></tr><tr><td><strong>Rodar a partir do código-fonte</strong></td><td>Desenvolvedores que querem ler ou modificar o código</td><td>Node <code>~24</code>, pnpm <code>10.33.x</code></td></tr><tr><td><strong>Instalar no seu agente</strong></td><td>Pessoas que vivem no terminal</td><td>Uma CLI de agente de código já existente</td></tr></tbody></table>\n<p>O caminho mais rápido é o <strong>app desktop</strong> — baixe em <a href=\"https://open-design.ai/download\">open-design.ai/download</a>; ele detecta automaticamente as CLIs de agente que já estão no seu <code>PATH</code>. Para rodar a partir do código-fonte:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>Abra a URL local que ele exibe (ele usa uma porta dinâmica — não deixe nenhuma fixa no código). No primeiro lançamento, aponte o Open Design para o agente que você quer conduzindo o trabalho, ou use sua própria chave de API.</p>\n<h2 id=\"step-2--build-a-landing-page-that-converts\">Passo 2 — Construa uma landing page que converte</h2>\n<p>Esta é a primeira demonstração de Sean, e ela é o modelo para todo o resto:</p>\n<ol>\n<li><strong>Escolha um design system.</strong> Na demonstração ele escolhe o da Anthropic. Esta é sua proteção anti-slop — o agente herda a paleta, a tipografia e a linguagem de componentes daquela marca.</li>\n</ol>\n<p><img src=\"/tutorials/open-design-vibe-coders-dream-sean-kochel/02-design-systems.webp\" alt=\"A biblioteca integrada de design systems — pontos de partida com marcas reais.\">\n<em>A biblioteca de design systems: cada item decompõe uma marca real em paleta, tipografia, componentes e atmosfera visual que você pode reutilizar.</em></p>\n<ol start=\"2\">\n<li><strong>Faça o prompt da estrutura, não só do clima.</strong> Sean diz exatamente quais seções construir — onze delas — e cola o resumo executivo do seu PRD (visão de produto, definição do problema, usuário-alvo, solução proposta, funcionalidades principais) para que o texto tenha contexto real com que trabalhar.</li>\n<li><strong>Responda às perguntas de descoberta.</strong> Assim como o Claude Design, o Open Design faz perguntas de esclarecimento antes de escrever. Aqui ele recorre à sua <strong>skill de landing page SaaS</strong> para executar — e, como as skills são apenas arquivos, você poderia carregar suas próprias diretrizes de copywriting ou estrutura de seções como uma skill no lugar.</li>\n<li><strong>Deixe rodar.</strong> Cerca de cinco minutos depois ele tem uma primeira versão profissional — uma estrutura real orientada à conversão, uma tabela comparativa limpa, um card de estudo de caso com bom estilo, um FAQ sólido.</li>\n</ol>\n<p>Quer uma pegada diferente? Sean roda novamente exatamente o mesmo brief com um tom <strong>brutalista</strong> em vez de editorial e obtém um design significativamente diferente — mesma estrutura, pele diferente, porque o design system faz o trabalho pesado.</p>\n<h2 id=\"step-3--build-a-mobile-app-screen-by-screen\">Passo 3 — Construa um app mobile, tela por tela</h2>\n<p>Para a demonstração mobile, Sean trabalha uma tela de cada vez. Ele mantém o mesmo design system da Anthropic e, então, para cada tela, cola um prompt construído a partir do seu PRD — um feed inicial, uma tela de recomendação para “preencher as lacunas”, um registro de refeições ad-hoc. O agente faz suas perguntas de esclarecimento, monta um layout iOS e segue o design system escolhido nas três telas.</p>\n<p>A lição: <strong>a forma como você faz o prompt da UX é a maior parte do resultado.</strong> Quando ele reformula o mesmo app como uma interface de coaching baseada em chat, obtém um conjunto de telas radicalmente diferente — mas ainda coerente. O design system mantém tudo dentro da marca; seu prompt decide o paradigma.</p>\n<p><img src=\"/tutorials/open-design-vibe-coders-dream-sean-kochel/03-templates.webp\" alt=\"A biblioteca de templates — pontos de partida de protótipo, slide, imagem e vídeo.\">\n<em>A biblioteca de templates: pontos de partida de protótipo, slide, imagem e vídeo que você pode filtrar por tipo e fazer fork para começar.</em></p>\n<h2 id=\"step-4--go-multimodal-screens-to-desktop-app\">Passo 4 — Vá multimodal: das telas ao app desktop</h2>\n<p>A última demonstração mostra o truque multimodal. Sean <strong>tira screenshots das suas três telas mobile, joga-as em um novo chat e faz um pedido aberto</strong>: “monte uma versão web app dessa funcionalidade principal.” Cinco minutos depois ele tem uma tradução limpa para desktop em três painéis — navegação à esquerda, o canvas de trabalho no meio, uma visão de progresso à direita — com as interações de slash command também esboçadas.</p>\n<p>Mesmo um prompt vago somado a imagens de referência dá a você um ponto de partida utilizável. Com uma especificação adequada fica mais afiado, mas o ponto se mantém: você pode transitar fluidamente entre superfícies.</p>\n<h2 id=\"tips\">Dicas</h2>\n<ul>\n<li><strong>Sempre comece a partir de um design system.</strong> É a maior alavanca contra o visual de slop de IA.</li>\n<li><strong>Faça o prompt da estrutura de forma explícita.</strong> Liste as seções ou telas; cole contexto real de um PRD para que o texto não seja oco.</li>\n<li><strong>Apoie-se nas skills — e escreva as suas.</strong> Skills são apenas arquivos; carregue suas regras de copywriting ou paradigmas de UX diretamente no fluxo de trabalho.</li>\n<li><strong>Itere por conversa.</strong> Enquadramentos de UX diferentes produzem resultados muito diferentes; isso é uma vantagem, então experimente alguns.</li>\n<li><strong>Use imagens de referência.</strong> Tire screenshots de telas existentes e jogue-as para traduzir entre superfícies.</li>\n<li><strong>Lembre-se de que a saída é HTML.</strong> Foi feita para entrar em um projeto que você já começou.</li>\n</ul>\n<h2 id=\"faq\">FAQ</h2>\n<p><strong>Preciso usar um modelo específico?</strong>\nNão. O Open Design conduz qualquer agente que você tenha configurado — Claude Code, Codex, Cursor, Gemini, OpenCode e mais — ou sua própria chave de API. Sem aprisionamento a um provedor.</p>\n<p><strong>Como isso é diferente do Claude Design?</strong>\nMesma sensação familiar, mas gratuito, open-source, local-first, agnóstico a modelos e muito mais personalizável — você pode adicionar suas próprias skills e processos. Além de geração de imagem e vídeo que uma ferramenta de provedor único não oferece.</p>\n<p><strong>Posso integrar o que construo a um app existente?</strong>\nSim — as saídas são arquivos HTML, então foram feitas para entrar em um projeto que você já começou. Sean aborda fluxos de integração orientados por especificação em um vídeo complementar.</p>\n<p><strong>É gratuito?</strong>\nO app é open source sob a licença Apache-2.0 e gratuito para rodar localmente. Você só paga pelo uso de modelo e de mídia do agente e dos provedores que você conectar.</p>\n<hr>\n<p><em>Este guia em texto é baseado nas demonstrações práticas de Sean Kochel. Assista ao vídeo completo acima e <a href=\"https://www.youtube.com/watch?v=MmTBkDmunk4\">inscreva-se no canal de Sean Kochel</a> para mais fluxos de trabalho de construção com IA.</em></p>",
  },
  "it": {
    title: "Open Design è il sogno di ogni vibe coder",
    summary: "Un manuale operativo per vibe coder dedicato a Open Design: usa l'agente che già conosci, scegli un design system per eliminare l'effetto \"slop\" generato dall'AI, struttura il prompt per convertire e trasforma PRD grezzi in una landing page, un'app mobile e un'app desktop in pochi minuti. Basato sulle demo pratiche di Sean Kochel.",
    bodyHtml: "<p>Questa guida è un manuale operativo per vibe coder dedicato a Open Design: usa l'agente che già adoperi, scegli un design system così che il risultato non gridi “generato dall'AI”, struttura il prompt in modo che converta davvero, poi itera attraverso la conversazione. Segue le tre build consecutive che <strong>Sean Kochel</strong> realizza nelle <a href=\"https://www.youtube.com/watch?v=MmTBkDmunk4\">sue demo pratiche</a> — una landing page, un'app mobile e un'app desktop — riscritte e aggiornate alla versione attuale. Guarda il video qui sopra per la prova dal vivo, oppure continua a leggere per la versione scritta.</p>\n<p><img src=\"/tutorials/open-design-vibe-coders-dream-sean-kochel/01-workspace.webp\" alt=\"L'area di lavoro di Open Design — ciò che ti accoglie dopo l'installazione.\">\n<em>L'area di lavoro di Open Design — prototipi, presentazioni, immagini e video in un'unica tela ordinata e familiare.</em></p>\n<h2 id=\"what-is-open-design\">Cos'è Open Design?</h2>\n<p>Open Design è una piattaforma di design open-source e local-first che gira <strong>sopra il coding agent che già usi</strong>. Rileva le CLI già presenti sulla tua macchina — Claude Code, Codex, Cursor, Gemini, Copilot, OpenCode e un paio di dozzine di altre — e lascia che sia quell'agente a guidare la generazione. Come dice Sean: c'è uno strato CLI dove configuri il tuo agente, un system prompt che governa la qualità, e poi le parti che lo rendono prezioso — il supporto alle skill e una libreria approfondita di design system. Gli output sono veri file HTML, quindi tutto ciò che crei finisce direttamente nel tuo progetto reale.</p>\n<p>Perché i vibe coder se ne interessano:</p>\n<ul>\n<li><strong>Porta il tuo agente e la tua chiave</strong> — nessun secondo abbonamento, nessun lock-in del provider.</li>\n<li><strong>Gira in locale</strong> — l'output è HTML che puoi inserire direttamente nel tuo codebase.</li>\n<li><strong>I design system eliminano l'aspetto da AI-slop</strong> — parti da un brand reale invece che da una tela bianca.</li>\n<li><strong>Le skill sono personalizzabili</strong> — inserisci le tue regole di copywriting, i tuoi paradigmi UX o i tuoi processi.</li>\n<li><strong>Open source, Apache-2.0</strong> — leggilo, fai un fork, consegnaci lavori per i clienti.</li>\n</ul>\n<h2 id=\"the-two-problems-every-vibe-build-runs-into\">I due problemi in cui incappa ogni vibe build</h2>\n<p>Sean imposta l'intero flusso di lavoro attorno a due modalità di fallimento, e vale la pena nominarle perché il resto del manuale è il modo in cui le eviti:</p>\n<ol>\n<li><strong>Sembra AI slop.</strong> Gradienti generici, lo stesso font serif, una zuppa di container — non piace nemmeno a te.</li>\n<li><strong>Non è strutturato per fare il suo lavoro.</strong> Una landing page che non converte, un'app il cui flusso non ha senso.</li>\n</ol>\n<p>Un <strong>design system</strong> risolve il primo problema. Un <strong>prompt mirato con una struttura reale</strong> risolve il secondo. Tieni a mente entrambi per ogni build qui sotto.</p>\n<h2 id=\"step-1--install-and-pick-your-agent\">Passo 1 — Installa e scegli il tuo agente</h2>\n<p>Hai tre modi per iniziare:</p>\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n<table><thead><tr><th>Percorso</th><th>Ideale per</th><th>Requisiti</th></tr></thead><tbody><tr><td><strong>App desktop</strong></td><td>La maggior parte delle persone — zero configurazione</td><td>Nessuno. Basta scaricare e aprire.</td></tr><tr><td><strong>Esegui dai sorgenti</strong></td><td>Sviluppatori che vogliono leggere o modificare il codice</td><td>Node <code>~24</code>, pnpm <code>10.33.x</code></td></tr><tr><td><strong>Installa nel tuo agente</strong></td><td>Chi vive nel terminale</td><td>Una CLI di coding-agent già esistente</td></tr></tbody></table>\n<p>Il percorso più rapido è l'<strong>app desktop</strong> — scaricala da <a href=\"https://open-design.ai/download\">open-design.ai/download</a>; rileva automaticamente le CLI degli agenti già presenti nel tuo <code>PATH</code>. Per eseguire invece dai sorgenti:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>Apri l'URL locale che stampa (usa una porta dinamica — non fissarla nel codice). Al primo avvio, indica a Open Design l'agente con cui vuoi guidare il lavoro, oppure usa la tua chiave API.</p>\n<h2 id=\"step-2--build-a-landing-page-that-converts\">Passo 2 — Costruisci una landing page che converte</h2>\n<p>Questa è la prima demo di Sean, ed è il modello per tutto il resto:</p>\n<ol>\n<li><strong>Scegli un design system.</strong> Nella demo sceglie quello di Anthropic. È la tua barriera anti-slop — l'agente eredita la palette, la tipografia e il linguaggio dei componenti di quel brand.</li>\n</ol>\n<p><img src=\"/tutorials/open-design-vibe-coders-dream-sean-kochel/02-design-systems.webp\" alt=\"La libreria integrata di design system — punti di partenza basati su brand reali.\">\n<em>La libreria di design system: ogni voce scompone un brand reale in palette, tipografia, componenti e atmosfera visiva che puoi riutilizzare.</em></p>\n<ol start=\"2\">\n<li><strong>Definisci nel prompt la struttura, non solo il mood.</strong> Sean specifica esattamente quali sezioni costruire — undici — e incolla l'executive summary del suo PRD (visione di prodotto, descrizione del problema, utente target, soluzione proposta, funzionalità principali) così che il testo abbia un contesto reale su cui lavorare.</li>\n<li><strong>Rispondi alle domande di scoperta.</strong> Proprio come Claude Design, Open Design pone domande di chiarimento prima di scrivere. Qui ricorre alla sua <strong>skill per landing page SaaS</strong> per l'esecuzione — e poiché le skill sono semplici file, potresti caricare al loro posto le tue linee guida di copywriting o la tua struttura di sezioni.</li>\n<li><strong>Lascialo lavorare.</strong> Circa cinque minuti dopo ha una prima bozza professionale — una vera struttura orientata alla conversione, una tabella comparativa pulita, una scheda case-study ben curata, una solida FAQ.</li>\n</ol>\n<p>Vuoi un'atmosfera diversa? Sean rilancia lo stesso identico brief con un tono <strong>brutalista</strong> invece che editoriale e ottiene un design sensibilmente diverso — stessa struttura, pelle diversa, perché è il design system a fare il lavoro pesante.</p>\n<h2 id=\"step-3--build-a-mobile-app-screen-by-screen\">Passo 3 — Costruisci un'app mobile, schermata per schermata</h2>\n<p>Per la demo mobile, Sean lavora una schermata alla volta. Mantiene lo stesso design system di Anthropic, poi per ciascuna schermata incolla un prompt costruito a partire dal suo PRD — un feed home, una schermata di raccomandazioni “colma le lacune”, un diario alimentare ad-hoc. L'agente pone le sue domande di chiarimento, abbozza un layout iOS e aderisce al design system scelto su tutte e tre le schermate.</p>\n<p>La lezione: <strong>il modo in cui imposti nel prompt l'UX è gran parte del risultato.</strong> Quando riformula la stessa app come un'interfaccia di coaching chat-first, ottiene un insieme di schermate radicalmente diverso — ma comunque coerente. Il design system la mantiene in linea con il brand; il tuo prompt decide il paradigma.</p>\n<p><img src=\"/tutorials/open-design-vibe-coders-dream-sean-kochel/03-templates.webp\" alt=\"La libreria di template — punti di partenza per prototipi, slide, immagini e video.\">\n<em>La libreria di template: punti di partenza per prototipi, slide, immagini e video, filtrabili per tipo e pronti per un fork da cui iniziare.</em></p>\n<h2 id=\"step-4--go-multimodal-screens-to-desktop-app\">Passo 4 — Passa al multimodale: dalle schermate all'app desktop</h2>\n<p>L'ultima demo mostra il trucco multimodale. Sean <strong>cattura screenshot delle sue tre schermate mobile, le inserisce in una nuova chat e formula una richiesta aperta</strong>: “abbozza una versione web app di questa funzionalità principale.” Cinque minuti dopo ha una pulita trasposizione desktop a tre pannelli — la navigazione a sinistra, la tela di lavoro al centro, una vista di avanzamento a destra — con anche le interazioni tramite slash-command abbozzate.</p>\n<p>Persino un prompt vago più immagini di riferimento ti dà un punto di partenza utilizzabile. Con una specifica adeguata diventa più nitido, ma il concetto regge: puoi muoverti fluidamente tra le superfici.</p>\n<h2 id=\"tips\">Consigli</h2>\n<ul>\n<li><strong>Parti sempre da un design system.</strong> È la leva singola più potente contro l'aspetto da AI-slop.</li>\n<li><strong>Definisci la struttura esplicitamente nel prompt.</strong> Elenca le sezioni o le schermate; incolla un contesto reale da un PRD così che il testo non sia vuoto.</li>\n<li><strong>Appoggiati alle skill — e scrivi le tue.</strong> Le skill sono semplici file; carica le tue regole di copywriting o i tuoi paradigmi UX direttamente nel flusso di lavoro.</li>\n<li><strong>Itera attraverso la conversazione.</strong> Inquadrature UX diverse producono risultati molto diversi; è una caratteristica, quindi provane qualcuna.</li>\n<li><strong>Usa immagini di riferimento.</strong> Cattura screenshot di schermate esistenti e inseriscili per tradurre tra le superfici.</li>\n<li><strong>Ricorda che l'output è HTML.</strong> È pensato per essere inserito in un progetto che hai già avviato.</li>\n</ul>\n<h2 id=\"faq\">FAQ</h2>\n<p><strong>Devo usare un modello specifico?</strong>\nNo. Open Design guida qualunque agente tu abbia configurato — Claude Code, Codex, Cursor, Gemini, OpenCode e altri — oppure la tua chiave API. Nessun lock-in del provider.</p>\n<p><strong>In cosa è diverso da Claude Design?</strong>\nStessa sensazione familiare, ma gratuito, open-source, local-first, agnostico rispetto al modello e molto più personalizzabile — puoi aggiungere le tue skill e i tuoi processi. In più, generazione di immagini e video che uno strumento legato a un singolo provider non ti offre.</p>\n<p><strong>Posso unire ciò che costruisco in un'app esistente?</strong>\nSì — gli output sono file HTML, quindi sono pensati per essere inseriti in un progetto che hai già avviato. Sean illustra i flussi di merge guidati dalla specifica in un video di accompagnamento.</p>\n<p><strong>È gratuito?</strong>\nL'app è open source sotto licenza Apache-2.0 ed è gratuita da eseguire in locale. Paghi solo per l'uso del modello e dei media dell'agente e dei provider che colleghi.</p>\n<hr>\n<p><em>Questa guida scritta è basata sulle demo pratiche di Sean Kochel. Guarda il video completo qui sopra e <a href=\"https://www.youtube.com/watch?v=MmTBkDmunk4\">iscriviti a Sean Kochel</a> per altri workflow di build con l'AI.</em></p>",
  },
  "tr": {
    title: "Open Design, Her Vibe Coder'ın Hayalidir",
    summary: "Open Design için bir vibe-coder el kitabı — kendi agent'ınızı getirin, AI çöplüğü görünümünü ortadan kaldırmak için bir tasarım sistemi seçin, dönüşüm sağlayan bir yapı için prompt yazın ve kabataslak PRD'leri dakikalar içinde bir landing page'e, bir mobil uygulamaya ve bir masaüstü uygulamasına dönüştürün. Sean Kochel'in uygulamalı demolarına dayanmaktadır.",
    bodyHtml: "<p>Bu rehber, Open Design için bir vibe-coder el kitabıdır: zaten kullandığınız agent'ı getirin, çıktınızın \"AI üretimi\" diye bağırmaması için bir tasarım sistemi seçin, gerçekten dönüşüm sağlayan bir yapı için prompt yazın, ardından sohbet ederek iterasyon yapın. Bu rehber, <strong>Sean Kochel</strong>'in <a href=\"https://www.youtube.com/watch?v=MmTBkDmunk4\">uygulamalı demolarında</a> art arda çalıştırdığı üç yapıyı izler — bir landing page, bir mobil uygulama ve bir masaüstü uygulaması — güncel sürümle yeniden yazılmış ve güncellenmiştir. Canlı çalıştırma için yukarıdaki videoyu izleyin ya da yazılı sürüm için okumaya devam edin.</p>\n<p><img src=\"/tutorials/open-design-vibe-coders-dream-sean-kochel/01-workspace.webp\" alt=\"Open Design çalışma alanı — kurulumdan sonra karşılaştığınız ekran.\">\n<em>Open Design çalışma alanı — prototipler, sunum desteleri, görseller ve video tek bir sakin, tanıdık tuval üzerinde.</em></p>\n<h2 id=\"what-is-open-design\">Open Design nedir?</h2>\n<p>Open Design, <strong>zaten kullandığınız kodlama agent'ının üzerinde</strong> çalışan, açık kaynaklı ve yerel öncelikli bir tasarım platformudur. Makinenizde halihazırda bulunan CLI'ları algılar — Claude Code, Codex, Cursor, Gemini, Copilot, OpenCode ve birkaç düzine daha — ve üretimi o agent'ın yürütmesine olanak tanır. Sean'in deyimiyle: agent'ınızı yapılandırdığınız bir CLI katmanı, kaliteyi yönlendiren bir sistem prompt'u ve ardından onu değerli kılan unsurlar var — skill desteği ve derin bir tasarım sistemleri kütüphanesi. Çıktılar gerçek HTML dosyalarıdır, dolayısıyla yaptığınız her şey doğrudan asıl projenize aktarılır.</p>\n<p>Vibe coder'ların bunu neden önemsediği:</p>\n<ul>\n<li><strong>Kendi agent'ınızı ve anahtarınızı getirin</strong> — ikinci bir abonelik yok, sağlayıcıya bağımlılık yok.</li>\n<li><strong>Yerel olarak çalışır</strong> — çıktı, doğrudan kod tabanınıza alabileceğiniz HTML'dir.</li>\n<li><strong>Tasarım sistemleri AI çöplüğü görünümünü ortadan kaldırır</strong> — boş bir tuval yerine gerçek bir markadan başlayın.</li>\n<li><strong>Skill'ler özelleştirilebilir</strong> — kendi metin yazarlığı kurallarınızı, UX paradigmalarınızı veya süreçlerinizi ekleyin.</li>\n<li><strong>Açık kaynak, Apache-2.0</strong> — okuyun, fork'layın, müşteri işlerini bununla teslim edin.</li>\n</ul>\n<h2 id=\"the-two-problems-every-vibe-build-runs-into\">Her vibe yapısının karşılaştığı iki sorun</h2>\n<p>Sean tüm iş akışını iki başarısızlık modu etrafında çerçeveliyor ve el kitabının geri kalanı bunlardan nasıl kaçınacağınızı anlattığı için bunları adlandırmaya değer:</p>\n<ol>\n<li><strong>AI çöplüğü gibi görünüyor.</strong> Sıradan gradyanlar, hep aynı serif font, kutu çorbası — bunu siz bile beğenmiyorsunuz.</li>\n<li><strong>İşini yapacak şekilde yapılandırılmamış.</strong> Dönüşüm sağlamayan bir landing page, akışı mantıklı olmayan bir uygulama.</li>\n</ol>\n<p>Bir <strong>tasarım sistemi</strong> birinci sorunu çözer. <strong>Gerçek bir yapıya sahip, bilinçli bir prompt</strong> ikinci sorunu çözer. Aşağıdaki her yapıda ikisini de aklınızda tutun.</p>\n<h2 id=\"step-1--install-and-pick-your-agent\">Adım 1 — Kurun ve agent'ınızı seçin</h2>\n<p>İçeri girmenin üç yolu var:</p>\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n<table><thead><tr><th>Yol</th><th>En uygun olduğu durum</th><th>Gereksinimler</th></tr></thead><tbody><tr><td><strong>Masaüstü uygulaması</strong></td><td>Çoğu kişi — sıfır yapılandırma</td><td>Yok. Sadece indirin ve açın.</td></tr><tr><td><strong>Kaynaktan çalıştırma</strong></td><td>Kodu okumak veya değiştirmek isteyen geliştiriciler</td><td>Node <code>~24</code>, pnpm <code>10.33.x</code></td></tr><tr><td><strong>Agent'ınıza kurma</strong></td><td>Terminalde yaşayan kişiler</td><td>Mevcut bir kodlama-agent'ı CLI'ı</td></tr></tbody></table>\n<p>En hızlı yol <strong>masaüstü uygulamasıdır</strong> — onu <a href=\"https://open-design.ai/download\">open-design.ai/download</a> adresinden alın; <code>PATH</code>'inizde zaten bulunan agent CLI'larını otomatik olarak algılar. Bunun yerine kaynaktan çalıştırmak için:</p>\n<pre class=\"astro-code open-design-editorial\" style=\"background-color:#f7f1de;color:#15140f; overflow-x: auto;\" tabindex=\"0\" data-language=\"bash\"><code><span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">git</span><span style=\"color:#6E7448\"> clone</span><span style=\"color:#6E7448\"> https://github.com/nexu-io/open-design.git</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">cd</span><span style=\"color:#6E7448\"> open-design</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">corepack</span><span style=\"color:#6E7448\"> enable</span><span style=\"color:#5A5448\"> &#x26;&#x26;</span><span style=\"color:#15140F;font-weight:bold\"> pnpm</span><span style=\"color:#6E7448\"> install</span></span>\n<span class=\"line\"><span style=\"color:#15140F;font-weight:bold\">pnpm</span><span style=\"color:#6E7448\"> tools-dev</span><span style=\"color:#6E7448\"> run</span><span style=\"color:#6E7448\"> web</span></span></code></pre>\n<p>Yazdırdığı yerel URL'yi açın (dinamik bir port kullanır — bunu sabit kodlamayın). İlk başlatmada Open Design'ı işi yürütmesini istediğiniz agent'a yönlendirin ya da kendi API anahtarınızı getirin.</p>\n<h2 id=\"step-2--build-a-landing-page-that-converts\">Adım 2 — Dönüşüm sağlayan bir landing page oluşturun</h2>\n<p>Bu, Sean'in ilk demosu ve diğer her şeyin şablonu:</p>\n<ol>\n<li><strong>Bir tasarım sistemi seçin.</strong> Demoda Anthropic'inkini seçiyor. Bu, AI çöplüğüne karşı korkuluğunuz — agent o markanın paletini, tipografisini ve bileşen dilini devralır.</li>\n</ol>\n<p><img src=\"/tutorials/open-design-vibe-coders-dream-sean-kochel/02-design-systems.webp\" alt=\"Yerleşik tasarım-sistemleri kütüphanesi — gerçek marka başlangıç noktaları.\">\n<em>Tasarım-sistemleri kütüphanesi: her giriş, gerçek bir markayı yeniden kullanabileceğiniz palet, tipografi, bileşenler ve görsel atmosfere ayırır.</em></p>\n<ol start=\"2\">\n<li><strong>Sadece havayı değil, yapıyı da prompt'layın.</strong> Sean tam olarak hangi bölümleri oluşturacağını söylüyor — on bir tane — ve PRD'sinden yönetici özetini (ürün vizyonu, problem tanımı, hedef kullanıcı, önerilen çözüm, ana özellikler) yapıştırıyor; böylece metnin üzerinde çalışacağı gerçek bir bağlam oluyor.</li>\n<li><strong>Keşif sorularını yanıtlayın.</strong> Tıpkı Claude Design gibi, Open Design da yazmaya başlamadan önce açıklayıcı sorular sorar. Burada işi yürütmek için <strong>SaaS landing-page skill'ine</strong> başvurur — ve skill'ler birer dosya olduğu için, bunun yerine kendi metin yazarlığı yönergelerinizi ya da bölüm yapınızı bir skill olarak yükleyebilirsiniz.</li>\n<li><strong>Çalışmasına izin verin.</strong> Yaklaşık beş dakika sonra profesyonel bir ilk taslağı oluyor — gerçek, dönüşüm odaklı bir yapı, temiz bir karşılaştırma tablosu, şık tasarlanmış bir vaka çalışması kartı, sağlam bir SSS.</li>\n</ol>\n<p>Farklı bir his mi istiyorsunuz? Sean aynı brief'i editöryel yerine <strong>brutalist</strong> bir tonla yeniden çalıştırıyor ve belirgin biçimde farklı bir tasarım elde ediyor — aynı yapı, farklı bir görünüm, çünkü ağır işi tasarım sistemi yapıyor.</p>\n<h2 id=\"step-3--build-a-mobile-app-screen-by-screen\">Adım 3 — Bir mobil uygulamayı ekran ekran oluşturun</h2>\n<p>Mobil demo için Sean her seferinde tek bir ekran üzerinde çalışıyor. Aynı Anthropic tasarım sistemini koruyor, ardından her ekran için PRD'sinden oluşturulmuş bir prompt yapıştırıyor — bir ana akış, bir \"boşlukları doldur\" öneri ekranı, ad-hoc bir yemek günlüğü. Agent açıklayıcı sorularını soruyor, bir iOS düzeni taslağı oluşturuyor ve üç ekranın hepsinde seçilen tasarım sistemine bağlı kalıyor.</p>\n<p>Çıkarılacak ders: <strong>UX'i nasıl prompt'ladığınız sonucun büyük kısmıdır.</strong> Aynı uygulamayı sohbet öncelikli bir koçluk arayüzü olarak yeniden çerçevelediğinde, çılgınca farklı — ama yine de tutarlı — bir ekran seti elde ediyor. Tasarım sistemi onu markaya uygun tutuyor; paradigmaya prompt'unuz karar veriyor.</p>\n<p><img src=\"/tutorials/open-design-vibe-coders-dream-sean-kochel/03-templates.webp\" alt=\"Şablonlar kütüphanesi — prototip, sunum, görsel ve video başlangıç noktaları.\">\n<em>Şablonlar kütüphanesi: türüne göre filtreleyip başlamak için fork'layabileceğiniz prototip, sunum, görsel ve video başlangıç noktaları.</em></p>\n<h2 id=\"step-4--go-multimodal-screens-to-desktop-app\">Adım 4 — Multimodal'a geçin: ekranlardan masaüstü uygulamasına</h2>\n<p>Son demo, multimodal numarasını gösteriyor. Sean <strong>üç mobil ekranının ekran görüntüsünü alıyor, bunları yeni bir sohbete bırakıyor ve uçtan uca bir istek veriyor</strong>: \"bu temel işlevselliğin bir web uygulaması sürümünün taslağını oluştur.\" Beş dakika sonra temiz, üç panelli bir masaüstü çevirisine sahip oluyor — solda navigasyon, ortada çalışma tuvali, sağda bir ilerleme görünümü — slash-komut etkileşimleri de taslak olarak oluşturulmuş.</p>\n<p>Belirsiz bir prompt artı referans görseller bile size kullanılabilir bir başlangıç noktası verir. Düzgün bir spesifikasyonla daha keskinleşir, ama mesele şu: yüzeyler arasında akıcı biçimde geçiş yapabilirsiniz.</p>\n<h2 id=\"tips\">İpuçları</h2>\n<ul>\n<li><strong>Her zaman bir tasarım sisteminden başlayın.</strong> AI çöplüğü görünümüne karşı en büyük kaldıraç budur.</li>\n<li><strong>Yapıyı açıkça prompt'layın.</strong> Bölümleri veya ekranları listeleyin; metnin içi boş olmasın diye bir PRD'den gerçek bağlam yapıştırın.</li>\n<li><strong>Skill'lere yaslanın — ve kendinizinkini yazın.</strong> Skill'ler sadece dosyalardır; metin yazarlığı kurallarınızı veya UX paradigmalarınızı doğrudan iş akışına yükleyin.</li>\n<li><strong>Sohbet ederek iterasyon yapın.</strong> Farklı UX çerçeveleri çok farklı sonuçlar verir; bu bir özelliktir, bu yüzden birkaçını deneyin.</li>\n<li><strong>Referans görseller kullanın.</strong> Mevcut ekranların ekran görüntüsünü alın ve yüzeyler arasında çeviri yapmak için bırakın.</li>\n<li><strong>Çıktının HTML olduğunu unutmayın.</strong> Halihazırda başlattığınız bir projeye eklenecek şekilde inşa edilmiştir.</li>\n</ul>\n<h2 id=\"faq\">SSS</h2>\n<p><strong>Belirli bir model kullanmak zorunda mıyım?</strong>\nHayır. Open Design, yapılandırdığınız hangi agent'ı kullanıyorsa onu yürütür — Claude Code, Codex, Cursor, Gemini, OpenCode ve daha fazlası — ya da kendi API anahtarınızı. Sağlayıcıya bağımlılık yok.</p>\n<p><strong>Bunun Claude Design'dan farkı ne?</strong>\nAynı tanıdık his, ama ücretsiz, açık kaynaklı, yerel öncelikli, modelden bağımsız ve çok daha özelleştirilebilir — kendi skill'lerinizi ve süreçlerinizi ekleyebilirsiniz. Ayrıca tek sağlayıcılı bir aracın size vermediği görsel ve video üretimi.</p>\n<p><strong>Oluşturduğum şeyi mevcut bir uygulamaya birleştirebilir miyim?</strong>\nEvet — çıktılar HTML dosyalarıdır, dolayısıyla halihazırda başlattığınız bir projeye eklenmek üzere tasarlanmışlardır. Sean, spesifikasyon odaklı birleştirme iş akışlarını eşlik eden bir videoda ele alıyor.</p>\n<p><strong>Ücretsiz mi?</strong>\nUygulama Apache-2.0 altında açık kaynaktır ve yerel olarak çalıştırması ücretsizdir. Yalnızca bağladığınız agent ve sağlayıcıların model ve medya kullanımı için ödeme yaparsınız.</p>\n<hr>\n<p><em>Bu yazılı rehber, Sean Kochel'in uygulamalı demolarına dayanmaktadır. Yukarıdaki tam videoyu izleyin ve daha fazla AI yapım iş akışı için <a href=\"https://www.youtube.com/watch?v=MmTBkDmunk4\">Sean Kochel'e abone olun</a>.</em></p>",
  },
};
